BEGIN;
UPDATE decision_nodes SET body = E'**Unstable first trimester patient = ruptured ectopic until proven otherwise.** [1]\n\n**Immediate actions:**\n• 2 large-bore IVs, aggressive fluid resuscitation\n• Type & crossmatch, activate MTP if needed\n• **Bedside FAST exam** — free intraperitoneal fluid?\n• **Bedside pelvic ultrasound** — IUP present?\n\n**If free fluid + no IUP → ruptured ectopic:**\n• O-negative blood transfusion\n• **Emergent OB consult for surgical intervention**\n• Do NOT delay for beta-hCG or formal imaging\n\n94% of all ectopic pregnancy-related deaths are from hemorrhagic shock due to rupture. [2]\n\nRupture can occur at **very low beta-hCG levels**. Beta-hCG <1500 mIU/mL carries 2× higher risk of ectopic. [4]' WHERE id = 'ft-unstable-ectopic' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'Determine the primary presentation to guide workup.\n\nAll stable patients need:\n• Urine pregnancy test (if not done)\n• Focused obstetric history — [gravida/parity (TPAL)](#/info/ft-ob-history), prior ectopic, assisted reproductive technology\n• Focused physical exam including pelvic if indicated' WHERE id = 'ft-stable-branch' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**Bedside or formal transvaginal ultrasound** + quantitative beta-hCG.\n\nEmergency physicians have **99.96% negative predictive value** for ectopic when IUP identified on bedside US. [5]\n\n[Ectopic Pregnancy Sites & Risk Factors](#/info/ft-ectopic-risk)\n\n**Risk factors:** prior ectopic, PID/STI history, salpingitis, IUD in situ, smoking (>1 pack/day OR 4), assisted reproductive technology.\n\nNearly **half of patients** with ectopic will have NO risk factors. [1]' WHERE id = 'ft-us-eval' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'Intrauterine pregnancy confirmed on ultrasound.\n\nIn the **general population**, this essentially **rules out ectopic** (heterotopic risk: 1 in 4,000-30,000).\n\n**Exception — Assisted Reproductive Technology (ART):** Heterotopic pregnancy risk is **1 in 100**. Maintain suspicion if ART patient with IUP + concerning symptoms. [7]\n\nIf the patient has **vaginal bleeding with confirmed IUP**, evaluate for miscarriage spectrum.' WHERE id = 'ft-iup-confirmed' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'No IUP visualized. Beta-hCG below the **discriminatory zone**.\n\n**Discriminatory zone:** ACOG recommends conservatively ≥3500 mIU/mL (transvaginal US). Below this, a normal IUP may simply be too early to visualize. [8]\n\n**Serial beta-hCG monitoring:**\n• Normal viable IUP: beta-hCG rises **≥53% in 48 hours** [9]\n• Slower rise or plateau: concerning for ectopic or nonviable IUP\n• Declining levels: may indicate completed miscarriage\n\n**CRITICAL:** One-third of patients eventually diagnosed with ectopic had a beta-hCG rise of ≥53% at 48h, and 20% had decline mimicking miscarriage. [10]\n\n**Trends CANNOT reliably exclude ectopic.** Continue serial monitoring until definitive diagnosis.' WHERE id = 'ft-pul' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'Beta-hCG **≥3500 mIU/mL** with no IUP visualized.\n\nThis strongly suggests a **nonviable pregnancy** — either:\n• Nonviable IUP (missed miscarriage, complete miscarriage)\n• Ectopic pregnancy\n\n**Does not definitively diagnose ectopic.** OB consultation recommended for further evaluation and management.\n\nPatient should have close follow-up with serial beta-hCG and ultrasound until diagnosis is established.' WHERE id = 'ft-no-iup-high' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'Confirmed or highly suspected ectopic pregnancy.\n\n**All management in consultation with OB.**\n\nDetermine if patient is a candidate for medical vs surgical management.' WHERE id = 'ft-ectopic-confirmed' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'[Methotrexate](#/drug/methotrexate/ectopic pregnancy) — single-dose IM regimen in consultation with OB.\n\n**Candidates (all must apply):**\n• Hemodynamically stable\n• No fetal cardiac activity (FCA has OR 9.1 for failure) [12]\n• Beta-hCG <5000 mIU/mL (>5000 has OR 5.45 for failure) [11]\n• Reliable for follow-up\n• No contraindications to methotrexate\n\n**Absolute contraindications to methotrexate:**\n• Immunodeficiency\n• Cytopenia (anemia, leukopenia, thrombocytopenia)\n• Active pulmonary disease\n• Active peptic ulcer disease\n• Hepatic or renal dysfunction\n• Breastfeeding [13]\n\n**Follow-up:** Serial beta-hCG at day 4 and day 7 post-injection. Expect decline. If inadequate decline, repeat dose or surgical intervention.' WHERE id = 'ft-ectopic-medical' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**Emergent OB consult for surgical intervention.**\n\n**Indications:**\n• Hemodynamic instability / ruptured ectopic\n• Contraindications to methotrexate\n• Beta-hCG >5000 mIU/mL\n• Fetal cardiac activity present\n• Failed medical management\n• Unreliable for follow-up\n\n**Procedures (OB to determine):**\n• **Salpingostomy** — removes ectopic, preserves tube (consider if contralateral tube damaged)\n• **Salpingectomy** — removes entire tube with ectopic (preferred in most cases)\n\nFor ruptured ectopic: **emergent laparotomy**. Do not delay for additional workup.' WHERE id = 'ft-ectopic-surgical' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'Classify based on **cervical os status** and **ultrasound findings**.\n\n[Miscarriage Types & Findings](#/info/ft-miscarriage-types)\n\nMiscarriage rates: 9-17% (age 20-30), 20% (age 35), 40% (age 40). Approximately half are due to fetal chromosomal abnormalities. [14]\n\n**If fever + uterine tenderness → suspect septic abortion** — emergent OB consult, broad-spectrum IV antibiotics, surgical evacuation.' WHERE id = 'ft-miscarriage-type' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'Vaginal bleeding with a **viable IUP** (closed cervical os, fetal cardiac activity detected).\n\n**Prognosis:** If fetal cardiac activity is present, only **3.4%** progress to miscarriage. However, heavy bleeding may increase this to 11-18%. [15]\n\nSpotting alone has no significant increase in miscarriage risk (OR 1.1). Heavy bleeding + pain increases risk (OR 3.0). [15]\n\n**Management:**\n• Reassurance — most will have normal pregnancy\n• No evidence supports bed rest\n• Strict return precautions\n• Close OB follow-up\n\n**NOTE:** 2-fold increased risk of subsequent adverse outcomes (preterm birth, low birth weight) — ensure OB is aware. [16]' WHERE id = 'ft-threatened' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'All products of conception have passed. Uterus is empty on ultrasound. Cervical os is closed.\n\n**Management:**\n• Confirm with ultrasound — empty uterus, closed os\n• No further ED intervention needed\n• Serial beta-hCG should trend to zero\n• OB follow-up for confirmation of completed miscarriage\n• Emotional support and grief resources\n\n[Managing Communication Around Pregnancy Loss](#/info/ft-miscarriage-communication)' WHERE id = 'ft-complete' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**OB consultation** for definitive management plan.\n\nOptions for the stable patient (no clear superiority among them): [17]\n\n**If visible products in cervix:** Remove at bedside with ring forceps. Consider sending to pathology (especially in recurrent miscarriage).\n\n**Surgical management is MANDATORY** for patients with significant hemorrhage or hemodynamic instability.' WHERE id = 'ft-nonviable-mgmt' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'Allow natural passage of products of conception.\n\n**Success rate:** 50-80% will have complete miscarriage within **7-10 days**.\n\nHigher success in incomplete miscarriage (already-open os) vs missed miscarriage.\n\nUp to **40%** of patients initially managed expectantly or medically may ultimately require unplanned surgical management. [19]\n\n**Counsel patient:**\n• Expect cramping and bleeding (may be heavy)\n• Return to ED if soaking >1 pad/hour for 2+ hours, fever, or lightheadedness\n• OB follow-up within 1 week\n\n[Miscarriage Discharge Instructions](#/info/ft-miscarriage-discharge)' WHERE id = 'ft-expectant' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'[Misoprostol](#/drug/misoprostol/miscarriage) **800 mcg intravaginally** — single dose.\n\n**Efficacy:** 91% effective within 7 days. [18]\n\nHigh patient satisfaction rates when compared to surgical management.\n\nUp to 40% may require unplanned admission or surgical management. [19]\n\n**Contraindications:**\n• Hemodynamic instability (needs surgical evacuation)\n• Septic abortion\n• Confirmed ectopic pregnancy\n\n**Counsel patient:** Expect significant cramping and bleeding. Return precautions for heavy bleeding, fever, or worsening pain.\n\n[Miscarriage Discharge Instructions](#/info/ft-miscarriage-discharge)' WHERE id = 'ft-medical-miscarriage' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**Dilation & Curettage (D&C)** — most effective option.\n\n**Indications:**\n• Hemodynamic instability or significant hemorrhage (MANDATORY)\n• Patient preference\n• Failed medical or expectant management\n• Septic abortion\n\n**Advantages:**\n• Lowest rates of incomplete miscarriage, bleeding, and need for transfusion [17]\n• Definitive and rapid\n\nArranged through OB consultation — typically same-day or next-day procedure.\n\nConsider sending products to pathology for analysis, especially in recurrent miscarriage.' WHERE id = 'ft-surgical-miscarriage' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**Intrauterine infection** in the setting of miscarriage or therapeutic abortion.\n\n**Presentation:** fever, uterine tenderness, purulent cervical discharge.\n\n**EMERGENT management:**\n• Large-bore IV access, fluid resuscitation\n• Blood cultures\n• Broad-spectrum IV antibiotics (gentamicin + clindamycin + ampicillin)\n• **Emergent OB consult for surgical evacuation**\n• May progress rapidly to sepsis/septic shock\n\nDo not delay surgical evacuation for antibiotic therapy to take effect.' WHERE id = 'ft-septic' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**Check Rh status** in all patients with first trimester vaginal bleeding or miscarriage.\n\nACOG 2017: Whether to administer anti-D immune globulin in threatened miscarriage **at or before 12 weeks is controversial** — no evidence-based recommendation can be made. [20]\n\n**Reasonable approach:**\n• **Minimal bleeding, early first trimester:** May withhold\n• **Heavy bleeding or near 12 weeks:** Consider administration\n• **Discuss with your hospital OB department** for institutional policy\n\n**If indicated:**\n• [Rh(D) Immune Globulin](#/drug/rh-immune-globulin/first trimester) 50 mcg IM within 72 hours\n• If 50 mcg unavailable, 300 mcg dose can be substituted\n\n**Only for Rh(D)-negative AND unsensitized patients.**' WHERE id = 'ft-rh-rhogam' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**Nausea and vomiting of pregnancy (NVP)** affects 85% of pregnant women. **Hyperemesis gravidarum** (3%) is the most severe form.\n\nNVP is a **diagnosis of exclusion** — rule out other causes first.\n\nNVP is actually **protective** against pregnancy loss (nausea HR 0.44; nausea + vomiting HR 0.20). [21]\n\n[NVP Stepwise Treatment Pathway](#/info/ft-nvp-pathway)\n\n**Assess:** Can the patient tolerate oral medications?' WHERE id = 'ft-nvp-assess' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**First-line (ACOG Level A):** [22]\n• [Pyridoxine (B6)](#/drug/pyridoxine/nvp) 10-25 mg PO TID\n• OR [Pyridoxine](#/drug/pyridoxine/nvp) + [Doxylamine](#/drug/doxylamine/nvp) 12.5 mg PO TID\n\n**Non-pharmacologic adjuncts:**\n• **Ginger capsules** 250 mg PO QID\n• **P6 acupressure** wristband (reduced nausea, vomiting, ketonuria in RCT) [23]\n• Convert prenatal vitamin to **folic acid only** (reduces nausea trigger)\n\nPyridoxine + doxylamine is **superior** to pyridoxine alone. [22]\n\nDid first-line therapy improve symptoms?' WHERE id = 'ft-nvp-oral' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'Add one of the following to pyridoxine ± doxylamine:\n\n• [Dimenhydrinate](#/drug/dimenhydrinate/nvp) 50 mg PO QID (max 200 mg/day if also taking doxylamine)\n• [Diphenhydramine](#/drug/diphenhydramine/nvp) 50 mg PO QID\n• [Prochlorperazine](#/drug/prochlorperazine/nvp) 25 mg PR q12h\n• [Promethazine](#/drug/promethazine/nvp) 12.5 mg PO or PR q6h\n\nNo high-quality evidence supports one specific agent over another. [24]\n\nDid second-line therapy improve symptoms?' WHERE id = 'ft-nvp-oral-step2' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**IV fluid resuscitation:**\n• **D5NS** preferred over NS (slightly decreased nausea at 8-16h) [25]\n• Consider adding [Thiamine](#/drug/thiamine/hyperemesis) 100 mg IV if protracted vomiting (prevents Wernicke encephalopathy before glucose administration) [22]\n\n**Lab workup:** BMP (electrolytes, renal function), LFTs, urinalysis (ketonuria)\n\n**IV antiemetics — choose one:**\n• [Metoclopramide](#/drug/metoclopramide/nvp) 10 mg IV q8h — reasonable first choice, no fetal malformation risk\n• [Ondansetron](#/drug/ondansetron/nvp) 8 mg IV over 15 min q12h — effective but possible small risk of fetal cardiac abnormalities [26]\n• [Dimenhydrinate](#/drug/dimenhydrinate/nvp iv) 50 mg IV in 50 mL NS over 20 min q6h\n• [Promethazine](#/drug/promethazine/nvp iv) 12.5 mg IV q6h\n\n**Ondansetron:** Exhaust other options first given possible fetal cardiac risk. [26]\n\nDid IV therapy improve symptoms?' WHERE id = 'ft-nvp-iv' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**Hyperemesis gravidarum** — loss of ≥5% prepregnancy body weight with persistent nausea, vomiting, and ketonuria.\n\n**OB consultation and admission for:**\n• Continued IV rehydration (D5NS at 125 mL/hr)\n• Electrolyte monitoring and repletion\n• [Thiamine](#/drug/thiamine/hyperemesis) 100 mg IV daily (prevent Wernicke encephalopathy)\n• Parenteral antiemetic regimen\n• Nutritional assessment\n\nOne quarter of women with severe NVP have considered pregnancy termination due to symptoms. [21]' WHERE id = 'ft-hg-admit' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'First trimester patients can present with **nonobstetric conditions** that require modified diagnostic and treatment approaches.\n\n[Imaging Safety in Pregnancy](#/info/ft-imaging-safety)\n[Antibiotic Safety in Pregnancy](#/info/ft-abx-safety)' WHERE id = 'ft-nonob-branch' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**In pregnancy, asymptomatic bacteriuria MUST be treated** if discovered. Untreated asymptomatic bacteriuria has a 2.4% risk of progression to pyelonephritis (vs 0.6% with treatment). [27]\n\n**Send urine culture** — negative urinalysis does not reliably exclude bacteriuria.\n\n**First-line antibiotics (7-day course):**\n• [Amoxicillin](#/drug/amoxicillin/uti pregnancy) 875 mg PO BID\n• [Cephalexin](#/drug/cephalexin/uti pregnancy) 500 mg PO q6h\n• [Nitrofurantoin](#/drug/nitrofurantoin/uti pregnancy) 100 mg PO BID — likely safe, but ACOG recommends use in first trimester only "when no other suitable alternatives are available" [28]\n\n[Antibiotic Safety in Pregnancy](#/info/ft-abx-safety)\n\nLocal antibiotic resistance patterns should guide empiric therapy.' WHERE id = 'ft-uti-eval' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**Admit ALL pregnant patients with pyelonephritis** for initial IV antibiotics. Insufficient evidence for outpatient management. [29]\n\n**Treatment:**\n• [Ceftriaxone](#/drug/ceftriaxone/pyelonephritis pregnancy) 1 g IV daily\n• Continue IV until afebrile 48 hours\n• Transition to oral antibiotics (e.g., [Cephalexin](#/drug/cephalexin/uti pregnancy)) guided by culture sensitivities\n\nBilateral mild hydronephrosis is **normal** in pregnancy (from hormonal changes + uterine compression). Do not over-interpret this finding.\n\nPregnant patients with pyelonephritis have **increased rates of sepsis and septic shock** compared to nonpregnant patients. [1]' WHERE id = 'ft-pyelo' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'Most common surgical problem in pregnancy, though pregnant women are actually **less likely** to have appendicitis than age-matched nonpregnant women. [30]\n\n**Despite traditional teaching, RLQ pain is the most common location** at all gestational ages. [31]\n\nPeritonitis is more common in pregnant patients with appendicitis (OR 1.3). Peritonitis → 4× higher rate of preterm birth. [32]\n\n**Imaging algorithm:**\n1. **Ultrasound first** — but visualization rate as low as 7%, sensitivity only 18% [33]\n2. **MRI without contrast** — 94% sensitivity, 97% specificity. First trimester MRI is safe (no fetal risk to age 4). [34, 35]\n3. **CT abdomen/pelvis** — if US indeterminate and MRI unavailable. Single study does NOT exceed threshold for fetal harm. Discuss risks/benefits with patient. [36]\n\n**AVOID gadolinium** — associated with stillbirth, neonatal death, and rheumatologic conditions. [35]\n\n[Imaging Safety in Pregnancy](#/info/ft-imaging-safety)\n\n**Treatment: surgical.** No data support antibiotics-only strategy in pregnancy. All patients need surgical consultation. [1]' WHERE id = 'ft-appendicitis' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**48-hour follow-up** for repeat beta-hCG and ultrasound.\n\n**Discharge criteria:**\n• Hemodynamically stable\n• Normal vital signs\n• No US evidence of ruptured ectopic\n• Reliable for follow-up\n\n**Strict return precautions:**\n• Severe or worsening abdominal pain\n• Heavy vaginal bleeding (soaking >1 pad/hour)\n• Lightheadedness, dizziness, or syncope\n• Fever\n• Shoulder pain (referred from diaphragmatic irritation)\n\nContinue serial monitoring until definitive diagnosis established (IUP confirmed, ectopic diagnosed, or beta-hCG reaches zero confirming completed miscarriage). [1]' WHERE id = 'ft-dispo-pul' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'[Miscarriage Discharge Instructions](#/info/ft-miscarriage-discharge) — shareable patient handout\n\n**Provide:**\n• Clear explanation of diagnosis in compassionate, culturally sensitive manner [37]\n• Prescription for chosen management (misoprostol if medical, or expectant instructions)\n• Pain management: ibuprofen 600 mg PO q6h PRN\n• Grief counseling resources and pregnancy-loss support groups [37]\n\n**OB follow-up** within 1-2 weeks.\n\n**Return precautions:**\n• Soaking >1 pad/hour for 2+ consecutive hours\n• Fever >100.4°F (38°C)\n• Foul-smelling discharge\n• Lightheadedness or syncope\n• Persistent heavy bleeding beyond 2 weeks\n\nGrief takes different forms — give permission to grieve in their own way. [37]' WHERE id = 'ft-dispo-miscarriage' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**Discharge criteria:**\n• Tolerating oral intake\n• Normal vital signs\n• Electrolytes corrected (if checked)\n• Able to keep down oral medications\n\n**Prescriptions:**\n• [Pyridoxine](#/drug/pyridoxine/nvp) 25 mg PO TID ± [Doxylamine](#/drug/doxylamine/nvp) 12.5 mg PO TID\n• Consider generic pyridoxine + doxylamine instead of brand combination (significantly cheaper)\n• Second-line agent if needed\n\n**Counsel:**\n• Small, frequent meals\n• Avoid triggers (strong smells, fatty/spicy foods)\n• Ginger (250 mg capsules QID) and P6 acupressure wristband as adjuncts\n• OB follow-up within 1 week\n\n**Return if:** unable to keep down fluids for >12 hours, persistent vomiting, lightheadedness, dark urine.' WHERE id = 'ft-dispo-nvp' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**Admit if:**\n• Hemodynamic instability\n• Ruptured ectopic (OR)\n• Pyelonephritis (IV antibiotics)\n• Appendicitis (surgical)\n• Hyperemesis gravidarum refractory to ED treatment\n• Septic abortion\n\n**Discharge if:**\n• Hemodynamically stable\n• Diagnosis established or safe plan for outpatient follow-up\n• Able to tolerate oral intake and medications\n• Reliable for follow-up (especially PUL patients — 48h recheck)\n• Adequate pain control\n\n**ALL patients:** OB follow-up arranged. Clear return precautions documented.' WHERE id = 'ft-dispo-general' AND tree_id = 'first-trimester';
-- === hiv (34 nodes) ===
UPDATE decision_nodes SET body = E'[HIV ED Management Steps Summary](#/info/hiv-steps-summary) — quick reference.\n\nHIV is now a manageable chronic disease with HAART, but ~14% of HIV-infected persons remain unaware of their status, driving continued transmission. [1] Approximately 80% of new transmissions are from persons not yet diagnosed or not in regular care.\n\nThe ED plays a critical role in:\n• Identifying undiagnosed HIV infection\n• Managing complications of chronic HIV and its treatment\n• Initiating [PEP](#/tree/pep) for potential exposures\n• Referring candidates for PrEP\n\n**Key first step:** Determine the patient''s HIV disease status — this drives the entire differential diagnosis.' WHERE id = 'hiv-start' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**Ask the patient:**\n• Most recent CD4 count and viral load (or at least if VL is "undetectable")\n• Current antiretroviral medications and compliance\n• Prior opportunistic infections\n• Recent travel or sick contacts\n\nPatients unaware of their CD4/VL or not engaged in care should be considered at **higher risk** for OIs and complications of untreated infection. [4]\n\nCD4 counts and viral load can be ordered from the ED but results will typically not be available for real-time decision-making. An **absolute lymphocyte count <950 cells/mcL** may suggest CD4 <200, though guidelines do not advocate this as a reliable estimate. [5, 6]' WHERE id = 'hiv-status-assess' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'[HIV Testing & Screening Guide](#/info/hiv-testing-guide) — universal vs risk-based approach.\n\n**CDC (2006):** Routine opt-out HIV screening for ages 13-64 in healthcare settings where undiagnosed prevalence ≥0.1%. [3]\n**USPSTF (Grade A):** Routine screening ages 15-65. [7]\n**ACEP:** Endorsed ED HIV testing since 2007. [8]\n\n**High-risk patients who should NOT be missed:**\n• Sexually active MSM\n• Persons who inject drugs and their sex partners\n• Persons who exchange sex for money or drugs\n• Sex partners of HIV-infected persons\n• Patients with new STI diagnosis\n\n**Testing technology:**\n• **Fourth-generation (preferred):** Detects HIV antibody + p24 antigen — can identify infection as early as **2 weeks** post-exposure [9]\n• Rapid point-of-care tests available (fingerstick slightly less accurate than lab-based)\n• If acute infection suspected and 4th-gen test negative → **must send HIV viral load**\n\nA 2018 study of >200,000 ED patients showed 0.4% new-diagnosis yield with nontargeted 4th-gen screening, of which 14.5% were acute HIV. [9]' WHERE id = 'hiv-screening' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'[Acute Seroconversion Features](#/info/hiv-seroconversion-features) — clinical presentation guide.\n\nAfter HIV exposure, local viral replication occurs over several days before entering the bloodstream with high viremia. **75-90% of patients** develop an acute illness during seroconversion. [1]\n\n**Classic presentation:**\n• Fever, headache, malaise\n• Sore throat (**without exudate**)\n• Lymphadenopathy (generalized)\n• GI symptoms (nausea, diarrhea)\n\n**More distinctive features:**\n• Genital or mucocutaneous ulcers\n• Nondescript **macular rash** (face, trunk, upper extremities) — mimics viral exanthem\n• **Notably absent:** respiratory or pulmonary symptoms\n\nCD4 count may drop acutely during seroconversion, rarely causing OIs (e.g., thrush). CD4 typically rebounds once the body gains some viral control.\n\nThe syndrome lasts **weeks** and patients frequently seek ED evaluation.' WHERE id = 'hiv-seroconversion' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**Diagnosis of acute seroconversion is challenging:**\n\n• Third-generation (antibody-only) tests may miss early infection — **no longer recommended as first-line**\n• **Fourth-generation tests** (antibody + p24 antigen) can often identify infection as early as **2 weeks** post-exposure — preferred initial test [9]\n• Early infection can still be missed within 2 weeks of exposure\n\n**Critical rule:** When acute infection is suspected and 4th-gen test is NEGATIVE → **order HIV viral load.** [9]\n\n**Why diagnosis matters:**\n• Patients with acute infection have **extremely high viral loads** and are more infectious than at any other stage\n• Identification allows prompt referral and rapid ART initiation\n• Undetectable = untransmittable (U=U) — the PARTNER 2 study showed zero transmissions when HIV+ partner had undetectable VL [10, 11]\n\n**Window periods:**\n• 4th-gen test: ~2 weeks\n• 3rd-gen antibody test: ~3-4 weeks\n• Viral load: ~10 days (earliest detection)' WHERE id = 'hiv-seroconversion-testing' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**Confirmed or highly suspected new HIV infection:**\n\n**Immediate actions:**\n• Baseline labs: CBC, BMP, hepatic function, CD4 count, viral load\n• Screen for co-infections: hepatitis B, hepatitis C, syphilis (RPR/VDRL), other STIs\n• Pregnancy test if applicable\n\n**Rapid ART initiation:**\nCurrent HHS and IAS-USA guidelines recommend **same-day initiation** of ART for newly diagnosed patients — reduces time to viral suppression and improves linkage to care. [12, 13]\n\nMost initial regimens use an **INSTI + 2 NRTIs:**\n• [Biktarvy](#/drug/biktarvy/hiv treatment) (BIC/FTC/TAF) — preferred single-tablet regimen\n• [TDF/FTC](#/drug/tdf-ftc/hiv prep) + [Dolutegravir](#/drug/dolutegravir/hiv pep)\n\n**ED role:**\n• Urgent referral to HIV specialist for same-day or next-day appointment\n• Ensure baseline labs are drawn\n• Counsel on transmission risk and safe practices\n• Document for linkage-to-care programs\n\n**If the patient has acute seroconversion illness,** treat symptoms supportively while expediting referral.' WHERE id = 'hiv-new-diagnosis' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'Patients with **well-controlled HIV** (CD4 >200, undetectable VL, treatment-adherent) are living longer and now present with **typical diseases of aging**, adverse medication effects, and chronic inflammatory state complications rather than OIs. [14]\n\nTreat these patients similarly to immunocompetent individuals, with attention to:\n• Higher baseline cardiovascular risk\n• Chronic inflammatory state → hypercoagulability\n• Medication side effects and interactions\n\nWhat is the primary complaint?' WHERE id = 'hiv-well-controlled' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**Well-controlled HIV patients** develop **traditional pulmonary infections** of immunocompetent patients. **Streptococcus pneumoniae** is the most common cause of bacterial pneumonia — treatment does not differ from non-HIV patients. [15, 16]\n\n**Disposition** can mirror practice for non-HIV patients, as well-controlled patients have similar pneumonia mortality. CURB-65 can be applied, though one small study found higher mortality with scores ≥2 AND CD4 <200. [17]\n\n**COPD** is an increasing concern:\n• HIV patients smoke at **2× the rate** of the general population [18]\n• Lung injury from prior OIs and drug effects contribute\n• Chronic HIV may be an independent risk factor [19]\n• Treatment is the same as for non-HIV patients\n\n**Venous thromboembolism / PE:**\n• Chronic inflammatory state → **hypercoagulability** → higher VTE rates [20, 21]\n• Consider PE with pleuritic chest pain, dyspnea — even if COPD is known\n• PERC criteria may not be validated for HIV patients (HIV status not reported in original study)\n\n**Key pitfall:** Do not anchor on COPD for an HIV patient with pleuritic chest pain — consider PE.' WHERE id = 'hiv-respiratory' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'HIV patients have **increased cardiovascular risk** from multiple factors: traditional risk factors, chronic inflammatory state, and medication effects (metabolic syndrome, abacavir MI association). [22, 23]\n\n**Acute coronary syndromes:**\n• HIV and some treatments are associated with CAD **absent traditional risk factors**\n• Abacavir has been associated with MI in retrospective studies (not yet confirmed prospectively) [24, 25]\n• Do NOT dismiss ACS in younger HIV patients — age alone does not rule it out\n\n**Heart failure:**\n• Prevalence 7.2% in HIV vs 4.4% in controls (P <.0001) [26]\n• Hazard ratio 3.2 for developing HF compared to non-HIV patients [27]\n• Only slightly lower rates even in patients on ARVs\n\n**Venous thromboembolism:**\n• 2.6 per 1000 patient-years [28]\n• Risk factors: CD4 <200, VL >100,000, current/recent OIs [29]\n• Chronic inflammatory state is the primary driver\n\n**Management:** Standard evidence-based protocols. Be aware of **drug interactions** between ARVs and anticoagulants, statins, and antiarrhythmics — especially with PI-based regimens.' WHERE id = 'hiv-cardiovascular' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**Guide evaluation by CD4 count.** Even well-controlled HIV carries slightly higher cerebrovascular risk.\n\n**Stroke:**\n• Risk ratio **2.56** (95% CI 1.43-4.61) compared to non-HIV [30]\n• Multifactorial: inflammatory state, atherosclerosis, smoking, metabolic medication effects\n• Follow standard evidence-based stroke algorithms\n\n**HIV-associated neurocognitive disorder (HAND):**\n• Most frequently identified neurologic disorder in HIV\n• Subacute cognitive deficits, central motor abnormalities, behavioral changes\n• Does NOT meet criteria for dementia\n• Rates decrease with longer periods of undetectable virus [31]\n\n**CNS OIs** (toxo, crypto, PML) are rare with well-controlled disease but increase dramatically with CD4 <200 → see [Immunocompromised pathway](#/node/hiv-cns-oi)\n\n**Imaging considerations:**\n• Immunocompetent HIV patient with headache probably does not need CT\n• But if CD4 is decreasing → CNS OIs and malignancy risk increases → neuroimaging indicated\n• CT may require **contrast** to identify infections or lymphoma\n• MRI provides better identification of smaller lesions and leptomeningeal enhancement\n• LP required if meningitis suspected' WHERE id = 'hiv-neuro' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**Diarrhea** is one of the most common HIV presentations in the ED. Up to **60% of patients on treatment** report an episode in the prior month. [32]\n\n**In well-controlled patients, OIs are rarely the cause.** More common etiologies:\n• **Medication side effect** — leading diagnosis for isolated diarrhea [33]\n• HIV enteropathy\n• Same pathogens that affect non-HIV individuals\n\n**Critical exception: C. difficile** — more common in HIV than non-HIV patients. Careful history for recent antibiotics or hospitalizations. [34]\n\n**Hepatobiliary disease:**\n• **61% of HIV patients are co-infected with HCV** in a large US analysis [35]\n• 10% co-infected with HBV [36]\n• Nearly all ARVs have hepatotoxicity potential, worsened by viral hepatitis co-infection\n• ED visit is an opportunity to **screen for HCV** in HIV patients not previously tested\n\n**Atazanavir** (PI) inhibits UDP-glucuronosyltransferase → **indirect hyperbilirubinemia and jaundice** — benign, resolves when drug is stopped.\n\n**Key pitfall:** Do not assume diarrhea is always a medication side effect — exclude C. difficile and assess for red flags.' WHERE id = 'hiv-gi' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'Renal disease can be caused by HIV infection itself AND nephrotoxic medications.\n\n**Tenofovir disoproxil fumarate (TDF) nephrotoxicity:**\n• Can cause **Fanconi syndrome** — polyuria, polydipsia, dehydration [37]\n• Labs: elevated creatinine, reduced GFR, acidemia, hypochloremia, hypokalemia, hypophosphatemia\n• UA: glucosuria, proteinuria\n• Higher risk in patients with pre-existing renal impairment\n• **TAF (tenofovir alafenamide)** has reduced risk — better renal biomarkers out to 144 weeks [38]\n• Withhold TDF and other nephrotoxins (e.g., ibuprofen) while resuscitating\n\n**PI-associated nephrolithiasis (CRITICAL for ED):**\n• [Atazanavir](#/drug/atazanavir/nephrolithiasis) and indinavir cause kidney stones\n• PIs have poor solubility + significant urinary excretion → stone formation\n• **Stones are RADIOLUCENT** if composed purely of drug metabolites [39, 40]\n• May NOT be visible on standard noncontrast CT\n• Look for **secondary signs**: hydroureter, perinephric stranding\n• If ongoing symptoms → urology consult for ureteroscopy\n• Discuss with HIV provider regarding medication adjustment\n\n**AKI treatment** is the same as for non-HIV patients.' WHERE id = 'hiv-renal' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'[HIV System-Based Complications](#/info/hiv-system-complications) — comprehensive reference.\n\n**Hematologic:**\n• Cytopenias of all cell lines common — bone marrow suppression in uncontrolled HIV\n• Medication-induced anemia often macrocytic (diagnosis of exclusion) [28]\n• Higher VTE rates (2.6/1000 patient-years)\n• Evaluate for thrombotic thrombocytopenic purpura (TTP) if hemolytic anemia + thrombocytopenia [41]\n\n**Endocrine & Metabolic:**\n• Metabolic syndrome: dyslipidemia, insulin resistance, truncal obesity (HIV-associated lipodystrophy) [42, 43]\n• Thyrotoxicosis/Graves disease with immune reconstitution (IRIS) — 8-33 months after starting HAART [44]\n• Glucocorticoid deficiency from adrenal involvement in AIDS — consider in hypotensive AIDS patients\n• Diabetes: both ARVs (especially PIs) and chronic inflammation increase risk [45]\n\n**Musculoskeletal:**\n• Lower bone mineral density → increased **fracture risk** [46, 47]\n• Higher rates of **avascular necrosis** — HIV and ARVs both implicated\n• As CD4 drops: spinal infections, osteomyelitis, discitis, atypical organisms (TB, NTM) [48]\n\n**Psychiatric:**\n• Depression, anxiety, substance use disorders are highly prevalent [49]\n• **Demoralization syndrome** — similar to depression but without anhedonia; does NOT respond to antidepressants\n• New-onset mania → evaluate for organic etiology (especially in untreated disease)\n• Screen all HIV patients for suicidal/homicidal ideation\n\n**Dermatologic:**\n• Drug-related skin reactions common → medication noncompliance [50]\n• Folliculitis (MRSA most common pathogen), HSV, HPV warts, seborrheic dermatitis, molluscum\n• Disseminated VZV in poorly controlled HIV — can cross dermatomes, may be superinfected' WHERE id = 'hiv-other-systems' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**Weakness is one of the most challenging presentations** in HIV patients.\n\nCommon causes of weakness in non-HIV patients are also common in HIV:\n• **Sepsis** — from any source\n• **Metabolic:** Hypoglycemia, electrolyte derangements (K+, Ca2+, Na+)\n• **Carbon monoxide poisoning** (in winter months)\n• **Anemia** — medication-induced or HIV-related\n\n**HIV-specific considerations:**\n• **OIs** (if CD4 <200 or unknown) — PJP, TB, disseminated MAC\n• **Medication adverse effects** — lactic acidosis (rare with current NRTIs), Fanconi syndrome (TDF)\n• **Adrenal insufficiency** — consider in AIDS patients with hypotension\n• **Malignancy** — lymphoma, Kaposi sarcoma\n\n**Workup:**\n• CBC, BMP (glucose, K+, Ca2+, Na+), hepatic function, lactate, VBG\n• If CD4 unknown or <200: expand workup (cultures, CXR, CT as indicated)\n• Consider serum lactic acid if anion gap metabolic acidosis or severe illness\n• CD4 and viral load (results not available for ED decisions but guide outpatient management)\n\n**HIV patients receive ~4.5 lab tests per ED visit** compared to 3.5 for non-HIV patients. [4]' WHERE id = 'hiv-weakness' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'Patient has **CD4 <200, detectable viral load, not in care, or unknown status.** These patients are at risk for opportunistic infections AND chronic disease complications.\n\n**AIDS** is defined by CD4 <200 cells/mcL OR development of certain OIs or cancers.\n\n**After acute illness, untreated HIV has ~8-10 years of clinical latency** before AIDS develops. Many remain asymptomatic but have lymphadenopathy. Chronic untreated infection causes a persistent inflammatory state predisposing to CAD, VTE, and COPD. [1]\n\nWhat is the primary concern?' WHERE id = 'hiv-immunocompromised' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**Pneumocystis jirovecii pneumonia (PJP):**\n• Classic: indolent, **nonproductive cough** + exertional dyspnea\n• CXR: perihilar or **"batwing" infiltrate** (see image below)\n• **LDH typically elevated** — a normal LDH helps rule OUT PJP [51]\n• LDH is not specific (elevated in lymphoma, TB, toxoplasmosis)\n• Prophylaxis: [TMP-SMX](#/drug/tmp-smx/pjp prophylaxis) when CD4 <200\n\n**Tuberculosis:**\n• HIV patients at increased risk for both novel infection and reactivation\n• Risk increases with poorly controlled infection\n• In the US, most common in persons who inject drugs\n• Consider in any HIV patient with cough, fever, weight loss, night sweats\n\n**With disease progression and advanced immunosuppression:**\n• At risk for drug-resistant and atypical organisms\n• Consider expanding antibiotic coverage\n• Consult infectious disease\n\n**Treatment for common pneumonias** (Strep. pneumoniae) is the same as for non-HIV patients. [15, 16]' WHERE id = 'hiv-pulm-oi' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'CNS OIs typically do **not appear until CD4 <200.** Rates have decreased significantly with treatment adherence.\n\n**Toxoplasmosis:**\n• Ring-enhancing mass lesion(s) on contrast CT or MRI\n• Fever, headache, focal neurologic deficits, seizures\n• Most common CNS mass lesion in AIDS\n\n**Cryptococcal meningitis:**\n• Subacute headache, fever, meningismus\n• May have only headache with subtle findings\n• LP with opening pressure (often elevated), CSF cryptococcal antigen, India ink\n\n**Progressive multifocal leukoencephalopathy (PML):**\n• JC virus — progressive white matter lesions\n• Subacute cognitive decline, focal deficits without fever\n• No effective antiviral — treatment is immune reconstitution with ART\n\n**CNS lymphoma:**\n• Ring-enhancing lesion (can mimic toxoplasmosis)\n• Often periventricular\n\n**Imaging considerations:**\n• **Nonenhanced CT may miss lesions** — contrast required\n• **MRI is superior** for smaller lesions and leptomeningeal enhancement\n• LP required for suspected meningitis/encephalitis\n\n**Key pitfall:** Do not accept a normal nonenhanced CT in an immunocompromised patient with neurologic symptoms — get contrast or MRI.' WHERE id = 'hiv-cns-oi' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'As CD4 drops, GI OI risk increases significantly.\n\n**C. difficile** — more common in HIV vs non-HIV patients regardless of CD4 count. Careful history: recent antibiotics, hospitalizations. [34]\n\n**With progressive immunosuppression (CD4 <100-200):**\n• **Cryptosporidium** — watery diarrhea, can be chronic/severe\n• **Cytomegalovirus (CMV)** — bloody diarrhea, colitis, can cause perforation\n• **Microsporidiosis** — chronic watery diarrhea\n• **Mycobacterium avium complex (MAC)** — fever, weight loss, diarrhea, hepatosplenomegaly (usually CD4 <50)\n\n**Stool studies** guided by disease stage:\n• All patients: C. difficile toxin, bacterial cultures, ova/parasites\n• Immunosuppressed: add AFB stool culture, Cryptosporidium antigen, microsporidium stain, CMV evaluation\n\n**Key point:** Initiation of ART to restore GI immune function will help eradicate many of these OIs. Link patients to HIV care.\n\n**Hepatobiliary OIs:**\n• Acalculous cholecystitis (CMV, Cryptosporidium)\n• MAC hepatitis\n• Peliosis hepatis (Bartonella)' WHERE id = 'hiv-gi-oi' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**Constitutional symptoms:**\n• Fever, weight loss, night sweats → evaluate for disseminated MAC, TB, lymphoma\n• Pancytopenia from bone marrow suppression\n\n**Dermatologic:**\n• **Kaposi sarcoma** — purple-red nodular lesions (HHV-8 associated)\n• Disseminated VZV — can cross dermatomes, may be superinfected\n• Severe molluscum contagiosum, extensive seborrheic dermatitis\n• Oral hairy leukoplakia (EBV — cannot be scraped off, unlike thrush)\n\n**Ocular:**\n• **CMV retinitis** (CD4 <50) — "pizza pie" fundoscopy, painless vision loss\n• Refer urgently to ophthalmology\n\n**Oropharyngeal:**\n• Oral candidiasis (thrush) — suggests CD4 <200\n• Oral hairy leukoplakia\n• Aphthous ulcers\n\n**When to strongly consider AIDS:**\n• CD4 <200 (by definition) or CD4 unknown\n• Any OI or AIDS-defining cancer\n• Recurrent bacterial pneumonia\n• Cervical cancer, lymphoma\n\n**All immunocompromised patients need:**\n• Comprehensive physical exam including oral mucosa and skin\n• Low threshold for imaging\n• Infectious disease consultation' WHERE id = 'hiv-other-oi' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**Low threshold for admission** in immunocompromised HIV patients.\n\n**Admit if:**\n• Suspected or confirmed OI requiring inpatient treatment (PJP, cryptococcal meningitis, toxoplasmosis, CMV)\n• Hemodynamic instability, sepsis\n• CNS symptoms with abnormal imaging or LP\n• Inability to tolerate oral medications or nutrition\n• Social barriers to outpatient follow-up\n\n**If discharging:**\n• Urgent follow-up with HIV specialist or infectious disease (within 24-72 hours)\n• Ensure patient has access to medications\n• Emphasize linkage to care — this is a critical opportunity\n• Start or resume OI prophylaxis if indicated ([TMP-SMX](#/drug/tmp-smx/pjp prophylaxis) for CD4 <200)\n\n**Do NOT stop HAART** for GI side effects or most complaints — viral resistance develops with inconsistent compliance. Very few scenarios warrant stopping: **Stevens-Johnson syndrome** and **nevirapine-associated hepatic failure** are clear indications. [1]\n\n**Involve the patient''s HIV provider** or ID consultant in all decisions to modify or stop ART.' WHERE id = 'hiv-immunocompromised-disposition' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'[ARV Drug Classes & Side Effects](#/info/hiv-arv-classes) — comprehensive reference table.\n\nMost current regimens use an **INSTI + 2 NRTIs** (e.g., Biktarvy). INSTI-based regimens are preferred for tolerability, reduced pill burden, and faster viral suppression. [12, 13]\n\nWhich drug class or concern?' WHERE id = 'hiv-med-overview' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'NRTIs/NtRTIs inhibit reverse transcription of HIV RNA into DNA. Current drugs are relatively well tolerated. [12]\n\n**Tenofovir disoproxil fumarate (TDF):**\n• **Fanconi syndrome** — polyuria, polydipsia, dehydration, elevated creatinine [37]\n• Labs: acidemia, hypokalemia, hypophosphatemia, glucosuria, proteinuria\n• Bone density loss and fractures\n• **TAF** (tenofovir alafenamide) has reduced renal and bone toxicity [38]\n\n**Abacavir:**\n• **Hypersensitivity reaction** in 3-5% — fever, rash, GI/respiratory symptoms, usually within first 6 weeks [52]\n• Associated with **HLA-B*5701 allele** — screening is mandatory before starting\n• If HLA-B*5701 positive → abacavir is **contraindicated**\n• **NEVER rechallenge** after hypersensitivity — can be fatal\n• Retrospective association with **myocardial infarction** (not confirmed prospectively) [24, 25]\n\n**Class effects (rare with current drugs):**\n• GI upset, nausea, headache, insomnia\n• Lactic acidosis — extremely rare with current regimens\n• Transaminitis — rare\n\n**For PrEP:** Both TDF/FTC and TAF/FTC are FDA-approved. TAF/FTC is NOT approved for use in heterosexual women (not studied). [53, 54]' WHERE id = 'hiv-nrti-effects' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'NNRTIs directly bind and inactivate HIV reverse transcriptase. Examples: efavirenz, rilpivirine, doravirine, nevirapine, etravirine.\n\n**Efavirenz — neuropsychiatric effects:**\n• Vivid dreams, nightmares, insomnia, confusion (often resolve after first weeks) [55]\n• **Severe cases:** psychosis, suicidal ideation, attempted/completed suicide\n• **Immediate discontinuation** if severe psychosis or suicidality\n• Often avoided in patients with psychiatric history\n• Rilpivirine: may cause insomnia/depression but lower risk than efavirenz [13]\n\n**Doravirine (newest NNRTI):**\n• Fewer CNS adverse events than efavirenz [56, 57]\n• Favorable lipid profile\n• Most commonly used in treatment-experienced patients with limited options\n\n**Skin reactions (all NNRTIs):**\n• Rash, GI upset, headache, dizziness — common\n• Infrequently: **Stevens-Johnson syndrome, toxic epidermal necrolysis, erythema multiforme** (more common with nevirapine)\n\n**Nevirapine — hepatotoxicity:**\n• FDA black box warning (2000)\n• Most frequent in first 6 weeks\n• Higher risk: chronic hepatitis, female CD4 >250, male CD4 >400 [12, 13]\n• Can cause liver failure' WHERE id = 'hiv-nnrti-effects' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'PIs prevent cleavage of essential polyproteins needed for mature HIV virion production. Most common today: **atazanavir** and **darunavir**, used with a booster (low-dose ritonavir or cobicistat). [13]\n\n**Common side effects:** Nausea, diarrhea, abdominal discomfort.\n\n**Metabolic effects:**\n• Lipodystrophy (central fat accumulation, peripheral wasting)\n• Dyslipidemia, hypertriglyceridemia\n• Type 2 diabetes (less common with lower-dose ritonavir boosting)\n• Rarely: pancreatitis from hypertriglyceridemia\n\n**[Atazanavir](#/drug/atazanavir/hiv jaundice):**\n• Inhibits UDP-glucuronosyltransferase → **indirect hyperbilirubinemia and jaundice** — benign, resolves on discontinuation\n• **RADIOLUCENT kidney stones** — PIs have poor solubility and significant urinary excretion [39, 40]\n• Stones may NOT be seen on noncontrast CT — look for hydroureter, perinephric stranding\n• Requires **acidic environment** for absorption → PPIs and H2 blockers may interfere\n\n**Drug interactions (CRITICAL):**\n• PIs (especially boosted with ritonavir/cobicistat) inhibit **CYP3A4** → major interactions with anticoagulants, statins, corticosteroids, antiarrhythmics, antiepileptics, antidepressants [13]\n• Much higher interaction risk than INSTI or NNRTI regimens\n• See [Drug Interactions](#/node/hiv-drug-interactions)' WHERE id = 'hiv-pi-effects' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**Integrase strand transfer inhibitors (INSTIs):** Block incorporation of viral DNA into host cell DNA. First-line for most patients. [12, 13]\n\nExamples: [Biktarvy](#/drug/biktarvy/hiv treatment) (bictegravir), [Dolutegravir](#/drug/dolutegravir/hiv pep), elvitegravir/cobicistat, raltegravir.\n\n**Generally very well tolerated** — rare discontinuations in clinical trials.\n• ~90% of patients attain and maintain undetectable VL through 96 weeks [58]\n• Raltegravir has the lowest drug interaction risk\n• Elvitegravir requires cobicistat booster → higher drug interaction risk and GI intolerance\n\n**Dolutegravir pregnancy concern:**\n• Initial Botswana data showed 4 neural tube defects in dolutegravir-exposed pregnancies [59]\n• Subsequent studies: risk exists but is lower than initially feared\n• **Review guidelines before using dolutegravir for PEP in women of childbearing age**\n\n**Entry inhibitors (rarely used):**\n• **Enfuvirtide** — injection site nodules; largely replaced by INSTIs\n• **Maraviroc** — CCR5 blocker; rare hepatotoxicity, hypotension with renal impairment\n• **Ibalizumab** — monoclonal antibody; hypersensitivity risk during/after infusion\n• Reserved for treatment-experienced patients with limited options' WHERE id = 'hiv-insti-effects' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**CRITICAL:** Several NRTIs/NtRTIs have dual activity against HIV AND hepatitis B:\n• **Tenofovir alafenamide (TAF)**\n• **Tenofovir disoproxil fumarate (TDF)**\n• **Emtricitabine (FTC)**\n• **Lamivudine (3TC)**\n\n**If a patient co-infected with HBV stops any of these medications**, there is risk of **acute hepatitis B flare** — fatalities have been reported. [1, 36]\n\n~10% of HIV patients are co-infected with HBV. [36]\n\n**ED presentation:**\n• Patient recently stopped or ran out of ARV medication\n• Elevated transaminases, jaundice, RUQ pain\n• May progress to fulminant hepatic failure\n\n**Management:**\n• Supportive care\n• **Consult infectious disease** for treatment options and reinitiation of therapy\n• Evaluate for other etiologies of hepatitis in parallel\n• Do NOT delay specialist consultation\n\n**When to stop HAART (very few scenarios):**\n• Stevens-Johnson syndrome\n• Nevirapine-associated hepatic failure\n• All other decisions to stop → involve HIV provider' WHERE id = 'hiv-hbv-caution' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**PI-based regimens** (especially boosted with ritonavir or cobicistat) carry the highest risk of drug interactions through **CYP3A4 inhibition**. [13]\n\n**High-risk combinations in the ED:**\n• **Anticoagulants** — warfarin, DOACs: altered metabolism\n• **Statins** — lovastatin and simvastatin contraindicated with PIs; use atorvastatin/rosuvastatin with dose adjustment\n• **Corticosteroids** — fluticasone + ritonavir → iatrogenic Cushing syndrome\n• **Antiarrhythmics** — amiodarone, flecainide, lidocaine: levels may be dangerously altered\n• **Antiepileptics** — carbamazepine, phenytoin: bidirectional interactions\n• **Antimalarials, antidepressants** — various interactions\n\n**INSTI-based regimens** have fewer interactions but:\n• Dolutegravir/bictegravir: chelation with polyvalent cations (antacids, Ca2+, Fe2+)\n• Dolutegravir increases metformin levels\n\n**Atazanavir absorption** requires acidic environment — PPIs and H2 blockers interfere.\n\n**Before prescribing any new medication** to an HIV patient on PIs:\n• Use an HIV drug interaction checker\n• When in doubt, consult pharmacy or infectious disease\n\n**Key ED takeaway:** Always check drug interactions when prescribing to HIV patients, especially those on PI-based or cobicistat-boosted regimens.' WHERE id = 'hiv-drug-interactions' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'The ED plays a vital role in preventing new HIV infections through PEP and PrEP awareness. [1, 60]\n\nWhich prevention scenario?' WHERE id = 'hiv-prevention' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**PEP is most effective when given ASAP** — ideally within 2 hours of exposure.\n\n**NOT recommended when care is sought >72 hours after exposure.** [60]\n\n**Indications:** Sexual exposure, needlestick/percutaneous, mucous membrane exposure, sexual assault.\n\n**Preferred regimens (28 days):**\n• [Biktarvy](#/drug/biktarvy/hiv pep) 1 tablet daily — preferred single-tablet regimen\n• [TDF/FTC](#/drug/tdf-ftc/hiv pep) + [Dolutegravir](#/drug/dolutegravir/hiv pep) — alternative\n• [TDF/FTC](#/drug/tdf-ftc/hiv pep) + [Darunavir](#/drug/darunavir/hiv pep)/[Ritonavir](#/drug/ritonavir/hiv pep) — second alternative\n\n**Baseline testing:** HIV test on exposed patient.\n\n**Adherence is critical:** One study showed <60% follow-up rates and <25% completed full 28-day course. [61] Emphasize adherence and arrange follow-up.\n\n**For the complete PEP decision pathway** including exposure risk assessment, special populations, and follow-up: [Post Exposure Prophylaxis Consult](#/tree/pep)\n\nRisk of transmission depends on type of exposure and viral load of source. Undetectable viral load = virtually zero transmission risk (PARTNER 2 study). [10]' WHERE id = 'hiv-pep-overview' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**PrEP is highly effective:** PROUD trial showed **86% relative risk reduction** in HIV acquisition. IPREX and DISCOVER studies showed >90% reduction with daily adherence. [53, 54, 62]\n\n**FDA-approved PrEP regimens:**\n• [TDF/FTC](#/drug/tdf-ftc/hiv prep) (Truvada®) — approved for all genders\n• TAF/FTC (Descovy®) — approved for MSM and transgender women only (women not studied) [54]\n\n**PrEP follow-up protocol:**\n• Daily medication, follow-up every 3 months\n• HIV testing at each visit\n• STI symptom assessment, side effect evaluation\n• Renal function at 3 months, then every 6 months [53]\n\n**Who to refer from the ED:**\n• MSM (especially with recent STI diagnosis) [63, 64]\n• Persons who inject drugs and their sex partners\n• Persons exchanging sex for money or drugs\n• Sex partners of HIV-infected persons with detectable VL\n• Any patient requesting PrEP information\n\n**ED role:** Educate, provide referral to PrEP provider. Do NOT start PrEP from the ED without baseline HIV testing and renal function.' WHERE id = 'hiv-prep-referral' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**Admission criteria:**\n• Suspected or confirmed OI requiring inpatient treatment\n• Hemodynamic instability, sepsis, respiratory failure\n• CNS symptoms with concerning imaging or LP findings\n• New diagnosis with acute seroconversion illness and complications\n• Inability to tolerate oral medications\n• Social barriers to safe discharge and follow-up\n\n**Orders:**\n• Continue home HAART regimen (do NOT hold unless directed by ID)\n• Infectious disease consultation for OI management\n• CD4 count and viral load if not recently available\n• Screen for co-infections (HBV, HCV) if not previously documented\n• Medication reconciliation — alert pharmacy to ARV drug interactions\n\n**If patient has fallen out of care:**\n• Social work consultation for linkage to HIV services\n• This hospitalization is an opportunity to re-engage the patient in treatment' WHERE id = 'hiv-admit' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**Discharge criteria:**\n• Stable vital signs, able to tolerate PO\n• No suspected OI requiring inpatient treatment\n• Well-controlled HIV with manageable complaint\n• Reliable follow-up available\n\n**Discharge instructions:**\n• Continue all HIV medications as prescribed — **do NOT stop HAART**\n• Follow up with HIV provider within 1-2 weeks (or sooner per complaint)\n• Return for worsening symptoms, new fever, inability to take medications\n\n**Linkage to care opportunities:**\n• If not engaged in HIV care → provide contact information for local HIV clinic\n• If PEP started → arrange follow-up in 3-7 days for adherence check\n• If PrEP candidate identified → refer to PrEP provider\n• If newly diagnosed → urgent HIV specialist referral (same day if possible)\n• If untested → offer HIV testing before discharge or provide referral\n\n**The ED visit is a critical touchpoint** — 80% of new transmissions come from those not diagnosed or not in care. Identifying and linking these patients is one of the highest-impact interventions the ED can provide. [1]\n\n[Discharge Instructions](#/info/hiv-ed-discharge) — shareable patient handout' WHERE id = 'hiv-discharge' AND tree_id = 'hiv';
-- === ich (17 nodes) ===
UPDATE decision_nodes SET body = E'[ICH Steps Summary](#/info/ich-summary) — time-critical hemorrhage management.\n\nSpontaneous ICH accounts for 10–15% of all strokes with ~40% 30-day mortality. Early hemostatic therapy, BP control, and neurosurgical consultation are the cornerstones of acute management.\n\n**Immediate actions:**\n• Non-contrast CT head — confirm diagnosis, estimate hematoma volume\n• Establish IV access ×2\n• Activate stroke/neurosurgery team\n• NPO (potential surgical candidate)\n\n**Do NOT delay anticoagulant reversal while awaiting labs** — empiric reversal should be given immediately if clinical suspicion of anticoagulant use is high.' WHERE id = 'ich-start' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'**Initial labs:**\n• CBC, BMP, Mg, Phos\n• INR, PTT, fibrinogen\n• Anti-Xa level if on oral Xa inhibitors (apixaban, rivaroxaban)\n• Toxicology screen (if clinically warranted)\n• Type & screen\n• ABG/VBG if intubated\n\n**Hematoma volume (ABC/2):**\nA × B × C ÷ 2 (cm) = volume in mL\n• A = largest diameter on axial CT\n• B = perpendicular diameter on same slice\n• C = number of slices with hemorrhage × slice thickness\n• <30 mL = relatively favorable prognosis\n• >30 mL = moderate-to-severe\n\n[CT Markers of Expansion](#/info/ich-ct-markers) — swirl sign, black hole sign, spot sign\n\n**CT Angiography:** Obtain for nearly all patients unless classic hypertensive location in an older patient. **Mandatory** if:\n• Lobar ICH in patient <70 years\n• Deep/posterior fossa ICH in patient <45 years\n• Deep ICH in patient 45–70 without hypertension history\n\n**Serial CT:** Repeat at ~6h and 24h for stable patients. More frequent if neuro decline or sedated.' WHERE id = 'ich-labs' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'**Determine anticoagulant/antiplatelet status immediately.**\n\nDo NOT wait for lab results before initiating reversal — empiric reversal should begin as soon as the agent is identified.\n\n[Causes of ICH](#/info/ich-causes) — hypertensive, CAA, vascular malformation, coagulopathy' WHERE id = 'ich-anticoag' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'**Goal: INR <1.4 as rapidly as possible.**\n\n**First-line: [4-Factor PCC](#/drug/pcc-4factor/warfarin ich)**\n• 25–50 IU/kg IV based on INR and weight\n• Onset: 10–15 minutes\n• Superior to FFP — faster correction, less volume\n\n**PLUS [Vitamin K](#/drug/vitamin-k/warfarin ich)**\n• 10 mg IV slow push (over 15–30 min)\n• Prevents INR rebound after PCC wears off (6–8h)\n• IV route preferred — oral takes 12–24h\n\n**FFP** (15 mL/kg) only if PCC unavailable — slower, volume overload risk\n\n**Monitoring:**\n• Recheck INR 15–30 min post-PCC\n• If INR still >1.4 → repeat PCC dose\n• Recheck INR at 6h (Vitamin K sustains correction)' WHERE id = 'ich-warfarin-rev' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'**First-line: [Idarucizumab](#/drug/idarucizumab/dabigatran ich) (Praxbind)**\n• 5 g IV as two consecutive 2.5 g bolus doses\n• Onset: immediate — complete reversal within minutes\n• Specific monoclonal antibody fragment for dabigatran\n\n**If idarucizumab unavailable:**\n• [4-Factor PCC](#/drug/pcc-4factor/doac ich) 50 IU/kg IV\n• OR activated PCC (FEIBA) 50 IU/kg IV\n\n**Adjuncts:**\n• Hemodialysis can remove dabigatran (60% reduction in 2–3h) — consider if idarucizumab unavailable and severe bleeding\n• Activated charcoal 50 g if ingestion within 2h (intubated patients only)\n\n**Note:** Dabigatran is the only DOAC with a specific reversal agent.' WHERE id = 'ich-dabi-rev' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'**Applies to: apixaban, rivaroxaban, edoxaban**\n\n**Option 1: [4-Factor PCC](#/drug/pcc-4factor/doac ich)**\n• 50 IU/kg IV\n• Most widely available option\n• Onset: 15–30 minutes\n\n**Option 2: Andexanet alfa (Andexxa)**\n• Specific Xa inhibitor reversal agent\n• Dosing depends on agent and time since last dose\n• Note: recently withdrawn from US market due to thrombotic concerns — availability varies\n\n**If last dose within 2h (intubated patient):**\n• Activated charcoal 50 g via OG/NG tube\n\n**Monitoring:**\n• Anti-Xa levels if available (not required before treatment)\n• Repeat CT at 6h to assess for expansion\n• Watch for thrombotic complications post-reversal' WHERE id = 'ich-xa-rev' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'**Unfractionated Heparin (UFH):**\n• [Protamine](#/drug/protamine/heparin reversal) 1 mg per 100 units UFH given in prior 2–3h\n• Max single dose: 50 mg\n• Onset: 5 minutes — complete reversal\n• Check PTT 15 min after administration\n\n**LMWH (enoxaparin):**\n• [Protamine](#/drug/protamine/lmwh reversal) — partial reversal only (~60%)\n• If enoxaparin given within 8h: Protamine 1 mg per 1 mg enoxaparin\n• If 8–12h: Protamine 0.5 mg per 1 mg enoxaparin\n• If >12h: likely no benefit\n\n**Thrombolysis-associated ICH:**\n• Cryoprecipitate 10 units (to replenish fibrinogen)\n• [Tranexamic acid](#/drug/tranexamic-acid/ich hemostasis) 1 g IV\n• Target fibrinogen >200 mg/dL\n• Platelets if count <100,000' WHERE id = 'ich-heparin-rev' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'**Not on anticoagulation — consider adjunct measures:**\n\n**Tranexamic acid (TXA):**\n• [TXA](#/drug/tranexamic-acid/ich hemostasis) 1 g IV over 10 min (within 3h of onset)\n• Significant reduction in hematoma expansion (OR 0.82)\n• Did NOT improve mortality or functional outcomes in TICH-2\n• May be considered — TICH-3 trial underway\n\n**Antiplatelet agents:**\n• Platelet transfusion is **NOT recommended** (PATCH trial — worse outcomes)\n• DDAVP 0.3 mcg/kg IV may be considered (limited evidence, DASH pilot)\n\n**Thrombocytopenia:**\n• Target platelets >100,000 if possible\n• Transfuse platelets if count <100,000\n\n**Coagulation factors:**\n• Check fibrinogen — supplement with cryoprecipitate if <200 mg/dL\n• Correct any identified coagulopathy' WHERE id = 'ich-coag-adj' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'**Treat pain and anxiety FIRST** — hypertension may be secondary. Proper analgesia/sedation (especially in intubated patients) can significantly improve BP.\n\n**AHA/ASA 2022 BP Targets:**\n• SBP 150–220 → target **130–150 mmHg** (reasonable)\n• SBP >220 → target **140–180 mmHg** (less evidence)\n• **Avoid SBP <130** — potentially harmful\n• **Avoid drops >70 mmHg** in first hour\n\n**Timing:** Maximum benefit when started immediately (hematoma expansion risk highest in first 3h). Transition to oral agents after >24h if stable.\n\n**Preferred IV agents:**\n• [Clevidipine](#/drug/clevidipine/ich blood pressure) — smoothest titration (t½ ~1 min)\n• [Nicardipine](#/drug/nicardipine/ich blood pressure) — more widely available, less expensive\n• [Labetalol](#/drug/labetalol/ich blood pressure) — bolus dosing option\n\n**Avoid:** Nitroprusside, nitroglycerin, hydralazine — may increase ICP.' WHERE id = 'ich-bp' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'Hematoma location determines surgical approach and prognosis.\n\n**Supratentorial (most common):**\n• Basal ganglia/external capsule (60–65%)\n• Thalamus (15–20%)\n• Lobar (cortical)\n\n**Infratentorial:**\n• Cerebellar (5–10%) — unique urgency\n• Pontine (5%) — poor prognosis regardless\n\n**Intraventricular extension** occurs in >40% and worsens prognosis.' WHERE id = 'ich-location' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'**Evidence for surgical evacuation is limited:**\n\n**STITCH-I Trial** (1,033 patients): No benefit from early surgery overall. Possible trend toward benefit for hematomas within 1 cm of cortical surface and lobar hemorrhage with GCS 9–12.\n\n**STITCH-II Trial** (601 patients): Focused on predicted surgical benefit subgroup — still no significant difference vs conservative management.\n\n**Possible indications for craniotomy:**\n• Large hematoma with significant midline shift\n• Elevated ICP refractory to medical management\n• Hemorrhage secondary to resectable lesion (AVM, tumor)\n• Lobar location, no IVH extension, very early presentation\n\n**Emerging:** Minimally invasive surgery (MISTIE III) — may be more promising than traditional craniotomy.\n\n**Decompressive hemicraniectomy:** Consider for massive edema with impending herniation when other options exhausted.\n\nConsult neurosurgery for all supratentorial ICH — even if medical management planned initially.' WHERE id = 'ich-supra-surg' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'**The cerebellum is unique — patients may deteriorate rapidly (12–24h).**\n\nRisks of cerebellar hemorrhage:\n• Direct brainstem compression → catastrophic damage\n• 4th ventricle compression → obstructive hydrocephalus\n• Upward transtentorial herniation\n\n**Paradox:** Cerebellar ICH patients tend to have better prognosis than other ICH types IF timely surgical intervention is performed.\n\n**AHA/ASA 2022 — Immediate surgical evacuation if:**\n• Hematoma volume **>15 mL**\n• Neurological deterioration\n• Brainstem compression\n• Hydrocephalus\n\n**Important:** Ventriculostomy (EVD) alone without posterior fossa decompression is **NOT recommended** — increases risk of upward transtentorial herniation.\n\nEVD pressure may not accurately reflect posterior fossa pressure.\n\nConsult neurosurgery **immediately** — this is a time-critical surgical emergency.' WHERE id = 'ich-cerebellar-surg' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'**IVH occurs in >40% of ICH patients and worsens prognosis.**\n\nComplications:\n• Hydrocephalus and elevated ICP\n• Central (neurogenic) fever\n\n**External Ventricular Drain (EVD):**\n• **Indicated** for hydrocephalus contributing to reduced consciousness\n• Ideal candidate: initially well, then develops hydrocephalus with neuroworsening\n• **Caveat:** EVD increases survival but may not increase rate of good neurologic outcome\n\n**Intraventricular tPA (CLEAR III Trial):**\n• 500 patients randomized to intraventricular tPA vs saline via EVD\n• Improved survival but did NOT increase good functional outcomes\n• May be considered when: predominantly IVH without large parenchymal hematoma, and hydrocephalus might resolve with clot dissolution\n\nConsult neurosurgery for EVD placement. Monitor ICP continuously.' WHERE id = 'ich-ivh-evd' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'**Incidence:** ~10% convulsive seizures; subclinical seizure rate is substantially higher.\n\n**Risk factors:**\n• Cortical involvement (lobar hemorrhages)\n• Coexisting subarachnoid or subdural hemorrhage\n• Rebleeding\n\n**Continuous EEG monitoring indications:**\n• Impaired consciousness disproportionate to CT findings\n• Unexplained fluctuations in mental status\n• Any witnessed seizure or clinical signs of seizure\n\n**Treatment:**\n• **Seizure prophylaxis is NOT recommended** — prior evidence showed no benefit with phenytoin, and phenytoin has numerous side effects\n• **Treat witnessed seizure, EEG seizure, or nonconvulsive status epilepticus:**\n  – [Levetiracetam](#/drug/levetiracetam/ich seizure) 20 mg/kg IV (max 3000 mg) — preferred first-line\n  – Avoid phenytoin (may worsen outcomes in ICH)' WHERE id = 'ich-seizures' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'**Intracranial Pressure:**\n• ICP elevation from mass effect, perihematomal edema, and/or obstructive hydrocephalus\n• **Edema peaks at ~5–6 days** — anticipate delayed neurological deterioration\n• Boluses of hypertonic saline or hypertonic bicarbonate for acute ICP crisis (bridge to EVD or surgery)\n• Routine hypertonic saline not supported by evidence\n\n**Sodium:**\n• Avoid hyponatremia or rapid decreases in sodium — worsens cerebral edema\n• Target Na >135 mEq/L\n\n**Fever:**\n• Treat aggressively with acetaminophen — also provides analgesic benefit\n• **Neurogenic fever** may occur, especially with IVH extension — diagnosis of exclusion\n• Work up infection first (blood/urine cultures, CXR)\n• For refractory neurogenic fever: bromocriptine\n• INTREPID trial: automated surface cooling does NOT improve outcomes — do not use enforced normothermia devices routinely' WHERE id = 'ich-icp-fever' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'**AHA/ASA 2022 recommendations:**\n\n**Immediately:**\n• Intermittent pneumatic compression (IPC) — start on admission\n\n**After 24–48 hours:**\n• If ICH has demonstrated stability on serial imaging:\n  – Low-dose [UFH](#/drug/ufh/dvt prophylaxis) 5000 units SQ q8–12h\n  – OR [Enoxaparin](#/drug/enoxaparin/dvt prophylaxis) 40 mg SQ daily\n  – Starting chemical DVT prophylaxis is reasonable\n\n**Caution:**\n• Patients with underlying coagulopathy or imaging evidence of ongoing hemorrhage expansion may require individualized approach\n• Weigh bleeding risk vs thromboembolism risk (ICH patients are immobilized, high VTE risk)\n\nHigh-risk for DVT: immobilization, weakness/paralysis, older age, obesity.' WHERE id = 'ich-dvt' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'**All ICH patients → ICU admission** for continuous neuro monitoring and BP management.\n\n**Ongoing care:**\n• Neuro checks q1h minimum (more frequent during acute phase)\n• Serial CT: 6h, 24h, and with any neuro decline\n• ICP monitoring if EVD placed\n• Transition IV antihypertensives to PO after >24h if stable\n• DVT prophylaxis per protocol\n• Early rehabilitation consultation\n• Goals of care discussion with family — especially for severe ICH\n\n**Prognostication:**\n• [ICH Score](#/calculator/ich-score) — 30-day mortality prediction (0–6 points)\n• [FUNC Score](#/calculator/func-score) — 90-day functional independence (0–11 points)\n• [Prognostication Details & Limitations](#/info/ich-prognostication)\n\n**Overall prognosis:**\n• 30-day mortality: ~40%\n• 1-year survival: ~50%\n• Functional independence at 1 year: ~20%\n\n**[Cerebral Amyloid Angiopathy](#/info/ich-caa)** — if lobar ICH in elderly, normotensive patient\n\nRestart anticoagulation decisions should be individualized (typically deferred ≥4 weeks, and avoided entirely in CAA).' WHERE id = 'ich-disposition' AND tree_id = 'ich';
-- === meningitis (28 nodes) ===
UPDATE decision_nodes SET body = E'[Meningitis/Encephalitis Steps Summary](#/info/mening-steps-summary) — quick reference.\n\nInfectious meningitis and encephalitis are life-threatening conditions requiring **time-critical empiric treatment**. Untreated bacterial meningitis approaches **100% mortality**; even with therapy, mortality is **14–25%**. [1,3,5]\n\nHerpes simplex encephalitis mortality was **70%** prior to antiviral therapy; now **~9%** with treatment. [7]\n\n• **Meningitis** = inflammation of meninges and subarachnoid space\n• **Encephalitis** = inflammation of brain parenchyma itself\n• Focal neurological deficits indicate brain tissue involvement (encephalitis) [8]\n\n**Key principle:** Empiric antimicrobials must be given **within 1 hour** of suspicion — do NOT delay for imaging or LP. [1,19]' WHERE id = 'mening-start' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'The classic triad of **fever, neck stiffness, and altered mental status** is present in only **44–66%** of bacterial meningitis cases. [3,5]\n\nHowever, when **headache** is added as a 4th symptom:\n• At least **2 of 4** symptoms are present in **95%** of cases [5]\n• At least **1 of 4** is present in **99–100%** of cases [5]\n\n**Stated differently:** Absence of ALL 4 symptoms (headache, fever, neck stiffness, altered mental status) effectively **rules out** meningitis/encephalitis. [9]\n\n**Individual symptom frequencies in ABM:**\n• Headache: 84–87%\n• Fever: 78%\n• Neck stiffness: 73–83%\n• Altered mental status (GCS <14): 79–80% [5]\n\n**Risk factors to elicit:** Immunocompromise (HIV, transplant, immunosuppressants), recent neurosurgery, CSF leaks, basilar skull fracture, recent otitis/sinusitis, herpes history, travel/geographic exposure, animal/insect contact, vaccination status. [9,22,25]' WHERE id = 'mening-clinical' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'**Kernig and Brudzinski signs:**\n• Sensitivity: only **2%** (essentially useless for ruling out) [13]\n• Specificity: **97–98%** (useful when positive, but rarely positive) [13]\n\n**Jolt accentuation of headache:**\n• Originally reported sensitivity 65–97%, but subsequent studies show only **21% sensitivity**, 82% specificity [13]\n• Inadequate to confirm or refute diagnosis\n\n**Key exam findings suggesting specific etiologies:**\n• Petechial rash (palms/soles) → *N. meningitidis* (also other bacterial causes) [9]\n• Dermatomal vesicular rash → VZV meningitis/encephalitis [6]\n• Swollen parotid glands (unvaccinated) → mumps [6]\n\n**Findings suggesting encephalitis (brain parenchyma involvement):**\n• Motor weakness / hemiparesis\n• Aphasia\n• Personality changes, hallucinations, psychosis\n• Dysautonomia\n• Seizures [8]' WHERE id = 'mening-exam' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'Focal deficits (hemiparesis, aphasia, personality changes, seizures) indicate **brain parenchyma involvement** and the presence of **encephalitis** rather than isolated meningitis. [8]\n\nThis distinction guides both the diagnostic workup (MRI utility) and empiric treatment (acyclovir).' WHERE id = 'mening-focal-deficits' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'**Immediately start empiric treatment:**\n• [Acyclovir](#/drug/acyclovir/encephalitis) 10 mg/kg IV q8h (HSV-1 most common endemic cause) [7]\n• PLUS empiric bacterial meningitis coverage (see next steps) [1]\n\n**CT is indicated** in all patients with focal deficits (mass lesion must be excluded before LP). [12,18]\n\n**MRI** is superior to CT for detecting encephalitis and can distinguish subtypes (e.g., HSV → temporal lobe involvement), but should not delay treatment. [8]\n\nHerpes simplex encephalitis mortality: **70% untreated → 9% with acyclovir**. [7,15]' WHERE id = 'mening-encephalitis-pathway' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'[CT Before LP Criteria](#/info/mening-ct-criteria) — international guideline comparison.\n\nCT is NOT needed before LP in most patients. CT is insensitive for meningitis/encephalitis. [12]\n\nHerniation after LP is rare: only **0.1%** deteriorated within 1 hour, and **91%** who deteriorated had a prior normal CT. [18]\n\n**CT IS indicated before LP if ANY of the following:** [12,15]' WHERE id = 'mening-ct-decision' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'**CRITICAL:** Start empiric antibiotics and [Dexamethasone](#/drug/dexamethasone/meningitis) BEFORE CT imaging. Do NOT delay treatment for any diagnostic test. [1,19,20]\n\nDelayed antibiotics correlate with disease progression and **increased mortality**. [19,20]\n\nAfter CT:\n• If no mass lesion or contraindication → proceed to LP\n• If mass lesion found → neurosurgical consultation; continue empiric treatment\n\n**Blood cultures** should be drawn before antibiotics when possible (66% yield in ABM). [5]' WHERE id = 'mening-abx-then-ct' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'No indications for CT before LP — proceed directly.\n\n**Start empiric antibiotics within 1 hour** of suspicion, ideally immediately after LP. [1]\n\nIf LP will be delayed for any reason, start antibiotics **first** — never wait. Antibiotics before LP reduce culture sensitivity but PCR remains reliable for days. [11,12]\n\n**Blood cultures** should be drawn before antibiotics (66% yield in ABM). [5]' WHERE id = 'mening-lp-direct' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'[CSF Interpretation Guide](#/info/mening-csf-guide) — reference for interpreting results.\n\n**Position:** Lateral decubitus if opening pressure measurement desired.\n\n**Collect 4 tubes (up to 15 mL safely):** [14,23]\n• **Tube 1:** WBC and RBC count\n• **Tube 2:** Protein, glucose, lactate, PCR\n• **Tube 3:** Gram stain, cultures, antigen tests, additional PCR\n• **Tube 4:** WBC and RBC count (compare to Tube 1 for traumatic tap)\n\n**Larger volumes increase sensitivity** of diagnostic tests. CSF is produced at 22 mL/hr. [14]\n\n**Traumatic tap?** Use the [CSF Traumatic Tap Correction](#/calculator/csf-correction) calculator to determine predicted WBC from RBC contamination.\n\n**Opening pressure:**\n• Normal: <20 cm H₂O\n• Elevated in bacterial meningitis; >40 cm H₂O in 39% of ABM cases [5,14]' WHERE id = 'mening-lp-technique' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'[Empiric Antimicrobial Table](#/info/mening-abx-table) — full regimens by risk category.\n\n**Antibiotics within 1 HOUR of suspicion.** [1]\n\nA retrospective study of 269 ABM episodes over 25 years demonstrated that delayed antibiotics correlated with **disease progression and increased mortality**. [19]\n\nAnother study of 119 ABM patients showed an **incremental association** between longer delays to antimicrobials and mortality. [20]\n\n**For ALL suspected bacterial meningitis:**\n• [Dexamethasone](#/drug/dexamethasone/meningitis) 0.15 mg/kg IV q6h × 2–4 days — give WITH or up to 15–20 min BEFORE first antibiotic dose [1,21]\n• Add [Acyclovir](#/drug/acyclovir/encephalitis) 10 mg/kg IV q8h if ANY encephalitis features [7]' WHERE id = 'mening-empiric-timing' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'**Targets:** *S. pneumoniae* (most common), *N. meningitidis* [2]\n\n**Regimen:**\n• [Ceftriaxone](#/drug/ceftriaxone/adult meningitis) 2g IV q12h (higher dose for CNS penetration) [1,24]\n• [Vancomycin](#/drug/vancomycin/meningitis) 15–20 mg/kg IV q8–12h (for cephalosporin-resistant pneumococci) [1,24]\n• [Dexamethasone](#/drug/dexamethasone/meningitis) 0.15 mg/kg IV q6h × 2–4 days [1,21]\n\n**Alternative:** [Meropenem](#/drug/meropenem/meningitis) 2g IV q8h if cephalosporin allergy or concern for multidrug-resistant organisms. [25]\n\n**Add [Acyclovir](#/drug/acyclovir/encephalitis)** 10 mg/kg IV q8h if ANY encephalitis features. [7]' WHERE id = 'mening-tx-standard' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'**Age ≥50, pregnant, or immunocompromised** patients are at increased risk for *L. monocytogenes* meningitis (mortality **17–30%**). [1,24]\n\nPregnant women are **10–20× more likely** to contract listerial infections. Infection during pregnancy is often devastating for the fetus. [24]\n\n**Regimen:**\n• [Ceftriaxone](#/drug/ceftriaxone/adult meningitis) 2g IV q12h [1]\n• [Vancomycin](#/drug/vancomycin/meningitis) 15–20 mg/kg IV q8–12h [1]\n• [Ampicillin](#/drug/ampicillin/adult meningitis) 2g IV q4h (Listeria coverage) [1,24]\n• [Dexamethasone](#/drug/dexamethasone/meningitis) 0.15 mg/kg IV q6h × 2–4 days [21]\n\n**Note:** [Meropenem](#/drug/meropenem/meningitis) has activity against *L. monocytogenes* — if used, ampicillin may be omitted. [1]\n\n**Add [Acyclovir](#/drug/acyclovir/encephalitis)** if encephalitis features present. [7]' WHERE id = 'mening-tx-expanded' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'**Risk factors:** Neurosurgical procedures, shunts/drains, CSF leaks, basilar skull fractures. [25]\n\n**Common pathogens:** Gram-negative bacilli (*P. aeruginosa*, *A. baumannii*), gram-positive skin flora (*Staphylococcus* spp including MRSA). Mortality: **16–41%**. [25]\n\n**Regimen:**\n• [Vancomycin](#/drug/vancomycin/meningitis) 15–20 mg/kg IV q8–12h (MRSA coverage) [25]\n• [Meropenem](#/drug/meropenem/meningitis) 2g IV q8h (broad gram-negative + Pseudomonas coverage) [25]\n• OR [Cefepime](#/drug/cefepime/adult meningitis) 2g IV q8h as alternative to meropenem [25]\n\n**CSF lactate** is particularly useful for diagnosis — postoperative inflammation alters conventional markers but does NOT affect lactate. [25]\n\nConsider Infectious Disease consultation for second-/third-line agents (linezolid). [25]' WHERE id = 'mening-tx-nosocomial' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'**Cryptococcal meningitis** is the 2nd highest cause of mortality in HIV/AIDS patients. *C. neoformans* causes ~1 million cases/year in HIV/AIDS, with ~600,000 annual deaths. [17]\n\nTypically subacute: weeks of evolving headache, neck stiffness, malaise.\n\n**Serum cryptococcal antigen (CrAg):** 99.7% sensitive, 94.1% specific — send immediately. [17]\n\n**Empiric antifungal regimen (after ID consultation):**\n• [Amphotericin B liposomal](#/drug/amphotericin-b/cryptococcal meningitis) 3–4 mg/kg/day IV [22]\n• [Flucytosine](#/drug/flucytosine/cryptococcal meningitis) 25 mg/kg PO q6h [22]\n• Induction × 1 week, then [Fluconazole](#/drug/fluconazole/cryptococcal meningitis) 400–800 mg/day [22]\n\n**ALSO give empiric bacterial coverage** (Ceftriaxone + Vancomycin + Ampicillin) until CSF results available. [1]\n\n**⚠️ Do NOT give corticosteroids** — associated with worsened outcomes in cryptococcal meningitis. [1,21]' WHERE id = 'mening-tx-crypto' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'No blood test can substitute for CSF analysis. Useful adjuncts:\n\n**Blood cultures:** Up to **66% yield** in ABM — collect before antibiotics. [5]\n\n**Serum procalcitonin (PCT):** Most discriminating biomarker for bacterial vs viral meningitis. [10,16]\n• PCT >0.25–0.5 ng/mL: **90–95% sensitivity, 98–100% specificity** for ABM [16]\n• More sensitive than any CSF marker for this purpose\n• Limited by availability in many EDs\n\n**C-reactive protein (CRP):**\n• CRP >37 mg/L: 85% sensitivity, 84% specificity for bacterial vs viral [10]\n• Reduced utility in elderly/immunocompromised\n\n**Serum cryptococcal antigen:** 99.7% sensitive for cryptococcal meningitis in immunocompromised patients. [17]\n\n**CBC:** Average WBC 17,500 in ABM vs 11,096 in viral — poor discriminatory value. [10]' WHERE id = 'mening-blood-tests' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'[CSF Interpretation Guide](#/info/mening-csf-guide) — detailed reference with normal values and patterns.\n\nCompare CSF results to expected patterns. **Note:** 6% of culture-proven ABM cases lack elevated WBC, and 10% have lymphocyte-predominant differentials. Early bacterial meningitis may mimic viral patterns. [1,14]' WHERE id = 'mening-csf-pattern' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'**Continue empiric antibiotics.** Await Gram stain, culture, and PCR for pathogen identification.\n\n**CSF Gram stain:** 60–99% sensitivity, 97–100% specificity. Sensitivity reduced after antibiotics. Negative Gram stain does NOT exclude bacterial meningitis. [5,14]\n\n**CSF culture:** Definitive diagnosis + antibiotic sensitivities. Sensitivity reduced **>30%** if LP performed >4 hours after antibiotics. *N. meningitidis* cultures may sterilize within 2 hours of antibiotics. [14]\n\n**CSF PCR:** Detects bacterial DNA even days after antibiotics — 87–100% sensitivity, 98–100% specificity. [12]\n\n**CSF lactate >35.1 mg/dL:** 93% sensitivity, 97% specificity for bacterial meningitis (when obtained before antibiotics). Particularly useful in healthcare-associated infections. [11]\n\n[Corticosteroid Guide](#/info/mening-steroid-guide) — continue dexamethasone for pneumococcal meningitis; discontinue if *Listeria* or *Cryptococcus* identified. [21]' WHERE id = 'mening-bacterial-mgmt' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'Viral meningitis is generally self-limited with lower morbidity than bacterial. However, viral **encephalitis** (especially HSV-1) has high mortality without treatment. [6,7]\n\n**Most common causes:** Non-polio enteroviruses (23–61%), HSV-2, arthropod-borne viruses. [6]\n\nAssess for encephalitis features:' WHERE id = 'mening-viral-branch' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'**HSV-1 is the most common endemic cause** of viral encephalitis in the Western world. [7]\n\n**[Acyclovir](#/drug/acyclovir/encephalitis) 10 mg/kg IV q8h** — continue for all suspected encephalitis. [7]\n• In the landmark RCT (208 patients): acyclovir reduced mortality from **70% to 28%** [7]\n• Contemporary mortality with acyclovir + ICU care: **~9%** [15]\n\n**If HSV-1 PCR negative but high clinical suspicion:**\n• Continue acyclovir — false-negative PCR is possible in the first **72 hours** [7]\n• Repeat PCR at **3–7 days** [7]\n\n**MRI findings:** Temporal lobe involvement is characteristic of HSV encephalitis. [8]\n\n**VZV encephalitis:** More common in immunocompromised patients. Continue acyclovir if VZV identified. [6]\n\n**⚠️ Corticosteroids** are NOT indicated for viral encephalitis (unlike bacterial meningitis). Consider if autoimmune encephalitis suspected (relapse weeks after initial infection — consult neurology). [1]' WHERE id = 'mening-encephalitis-tx' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'Viral meningitis is generally **self-limited** with lower mortality and fewer long-term complications than bacterial causes. [6]\n\n**Management:**\n• Supportive care: IV fluids, antiemetics, analgesics\n• No directed antiviral therapy has proven to affect outcomes for most viral causes [6]\n\n**Important caveats:**\n• Early bacterial meningitis may mimic viral patterns — 25% of *L. monocytogenes* cases have normal or near-normal CSF [1]\n• If ANY diagnostic uncertainty, continue empiric antibiotics and admit [14]\n• Patients with severe symptoms (refractory headache, persistent vomiting) may still require admission even with viral etiology\n\n**Disposition:** Some low-risk patients may be appropriate for discharge. See disposition criteria. [23]' WHERE id = 'mening-viral-mgmt' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'Fungal meningitis is primarily a disease of **immunocompromised** populations. Most cases present **subacutely** with weeks of evolving symptoms. [8]\n\n**Most common cause:** *Cryptococcus neoformans* (~1 million cases/year in HIV/AIDS). [17]\n\nOther causes: *Histoplasma*, *Coccidioides*, *Candida* species.\n\n**Treatment (requires ID consultation):**\n• **Induction (1 week):** [Amphotericin B liposomal](#/drug/amphotericin-b/cryptococcal meningitis) 3–4 mg/kg/day IV + [Flucytosine](#/drug/flucytosine/cryptococcal meningitis) 25 mg/kg PO q6h [22]\n• **Consolidation:** [Fluconazole](#/drug/fluconazole/cryptococcal meningitis) 400–800 mg/day PO [22]\n• This regimen showed lowest mortality in a Cochrane review of 13 studies (2426 participants) [22]\n\n**⚠️ Do NOT give corticosteroids** — dexamethasone is associated with **worsened outcomes** in cryptococcal and listerial meningitis. Discontinue immediately if either pathogen identified. [1,21]' WHERE id = 'mening-fungal-mgmt' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'**When in doubt, treat as bacterial meningitis.**\n\n**Key pitfalls with equivocal CSF:**\n• **6%** of culture-proven ABM cases have NO elevated WBC count [1,14]\n• **10%** of ABM cases have lymphocyte-predominant (not neutrophil) differentials [1,14]\n• **25%** of *L. monocytogenes* cases have normal or near-normal CSF findings [1]\n• Early in disease course, bacterial patterns may be incomplete\n• Prior antibiotic administration alters CSF findings\n\n**Management:**\n• Continue full empiric antibiotic regimen\n• Continue [Dexamethasone](#/drug/dexamethasone/meningitis) pending pathogen identification [21]\n• Admit for monitoring and repeat assessment\n• Await cultures, PCR, and repeat CSF if needed\n\n**CSF lactate >35.1 mg/dL** favors bacterial cause (93% sensitivity, 97% specificity pre-antibiotics). [11]\n**Serum PCT >0.25–0.5 ng/mL** strongly favors bacterial etiology (90–95% sensitivity). [16]' WHERE id = 'mening-equivocal' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'[Corticosteroid Guide](#/info/mening-steroid-guide) — detailed evidence and dosing.\n\n**[Dexamethasone](#/drug/dexamethasone/meningitis) 0.15 mg/kg IV q6h × 2–4 days** [1,21]\n\nGive WITH or up to **15–20 minutes BEFORE** first antibiotic dose. [1]\n\n**Evidence (Cochrane 2015, 25 studies, 4121 patients):**\n• Overall ABM: nonsignificant mortality reduction (17.8% vs 19.9%) [21]\n• **Pneumococcal meningitis in high-income countries:** significant mortality reduction [21]\n• **TB meningitis:** corticosteroids reduced mortality by ~25% at 18 months [21]\n\n**⚠️ STOP corticosteroids if pathogen is NOT *S. pneumoniae* or *M. tuberculosis*:**\n• *L. monocytogenes:* nonsignificant trend toward **worse outcomes** with corticosteroids [21]\n• *C. neoformans:* corticosteroids associated with **worsened outcomes** [1]\n\n[Postexposure Prophylaxis Guide](#/info/mening-pep-guide) — regimens for contacts of *N. meningitidis* and *H. influenzae*.' WHERE id = 'mening-steroids' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'[Disposition Criteria](#/info/mening-dispo-criteria) — discharge vs ward vs ICU criteria.\n\nMost patients with meningitis and encephalitis will be admitted. Determine appropriate level of care: [1,23]' WHERE id = 'mening-dispo' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'**Discharge criteria (extrapolated from pediatric data, use clinical judgment):** [23]\n• Nontoxic clinical appearance\n• Normal serum WBC count\n• Mild CSF pleocytosis only\n• Negative CSF Gram stain\n• Adequate symptom control (headache, nausea, vomiting)\n• Reliable support system and follow-up capability\n\n**Return precautions — discuss thoroughly:**\n• Worsening headache\n• Vomiting\n• Confusion or behavioral changes\n• Seizures\n• Fever >38.5°C\n• Neck stiffness worsening\n\n**Follow-up:** Primary care within **3 days** for reassessment. [23]\n\n[Discharge Instructions](#/info/meningitis-discharge) — shareable patient handout' WHERE id = 'mening-discharge' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'**Indications:**\n• Alert enough to maintain airway\n• Stable vital signs\n• Not receiving titratable medications\n• Does not require close neurological monitoring\n\n**Ward management:**\n• Continue IV antibiotics pending CSF analysis results\n• Tailor antimicrobial therapy once causative agent identified\n• Continue dexamethasone if bacterial meningitis suspected (discontinue if not *S. pneumoniae* or TB) [1,21]\n• Patients with viral meningitis who have severe symptoms (refractory headache, persistent vomiting) should be admitted for symptom management\n• Serial neurological assessments' WHERE id = 'mening-ward' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'**Indications:**\n• GCS score ≤8 — consider advanced airway management [8]\n• Hemodynamic instability requiring vasopressors\n• Seizure activity or focal neurological deficits\n• All cases of **severe encephalitis**\n• Rapidly declining level of consciousness\n\n**ICU capabilities required:**\n• Continuous electroencephalographic (EEG) monitoring\n• Intracranial pressure (ICP) monitoring capability\n• Frequent neurological reassessment\n• Advanced airway management\n• Titratable IV medications\n\n**⚠️ Osmotic agents and therapeutic hypothermia** are NOT recommended — studies stopped early due to concerns for increased mortality in treatment groups. [1]' WHERE id = 'mening-icu' AND tree_id = 'meningitis';
-- === neonatal-resus (27 nodes) ===
UPDATE decision_nodes SET body = E'[Algorithm — Quick Reference](#/node/nrp-algorithm-ref)\n[Setup and Tools — Quick Reference](#/node/nrp-setup-ref)\n[NRP Steps Summary](#/info/nrp-summary) — quick-reference checklist for neonatal resuscitation.\n\n**Neonatal resuscitation** follows a systematic, stepwise approach from initial assessment through advanced interventions.\n\n**Key statistics:** [1]\n• ~90% of newborns transition without intervention beyond warmth, drying, and stimulation\n• ~10% need early support (PPV, supplemental O2)\n• <1% need extensive resuscitation (CPR + medications)\n\n**Modules:**\n• Module 1: Preparation & Initial Assessment — team, equipment, cord management, initial evaluation\n• Module 2: Initial Steps — Golden 30 Seconds (warm, dry, position, stimulate, clear)\n• Module 3: Positive Pressure Ventilation — PPV technique, corrective steps, advanced airway\n• Module 4: Chest Compressions — CPR technique, intubation\n• Module 5: Medications & Vascular Access — epinephrine, UVC, volume resuscitation\n• Module 6: Post-Resuscitation — APGAR, normothermia, NICU transfer\n\n**Cross-links:**\n• [Precipitous Delivery](#/tree/precip-delivery) — ED delivery management\n• [Shoulder Dystocia](#/tree/shoulder-dystocia) — if turtle sign during delivery' WHERE id = 'nrp-start' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'TEAM BRIEFING\n• Assign roles before delivery: **team leader**, airway manager, compressor, medication nurse, timekeeper/recorder\n• NRP pre-brief questions: gestational age, number of babies, risk factors (meconium, preeclampsia, prematurity), cord management plan\n• Communicate: **"vigorous" vs "non-vigorous"** dictates cord strategy\n\nEQUIPMENT CHECKLIST\n• **Radiant warmer** — turn ON now (prewarming)\n• **T-piece resuscitator** (preferred 2025) or self-inflating bag with manometer\n• **Pulse oximeter** — right hand/wrist (preductal)\n• **Cardiac monitor** — 3-lead ECG (most accurate HR)\n• **Suction** — bulb syringe + wall suction with 10F/12F catheter\n• **Intubation** — laryngoscope (Miller 0/00), ETT (2.5–4.0), stylet, tape\n• **UVC kit** — umbilical catheter (3.5F/5F), umbilical tape, sterile instruments\n• **Medications** — epinephrine 1:10,000, normal saline, D10W\n\n**Document:** cord clamping time, APGARs, time to ventilation [1][2]' WHERE id = 'nrp-preparation' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'DELAYED CORD CLAMPING (DCC) — 2025 GUIDELINES [1][5]\n\n**Vigorous term/late preterm:**\n• DCC **30–60 seconds** recommended\n• Improves placental transfusion, iron stores, and hemoglobin\n\n**Non-vigorous ≥35 weeks:**\n• **Intact cord milking (ICM)** may be reasonable (compared to immediate clamping)\n• Milk cord toward baby 3–4 times over 2 seconds\n\n**Preterm 28–34 weeks:**\n• ICM when DCC isn''t possible\n\n**<28 weeks:**\n• ICM is **NOT recommended** — risk of intraventricular hemorrhage\n\n**Clamp immediately if:**\n• Baby needs resuscitation and can''t wait\n• Placental abruption, cord avulsion, or other emergency\n\n**Communicate cord management plan to the team before delivery.** [5]' WHERE id = 'nrp-cord-mgmt' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'PRETERM ASSESSMENT [1][2]\n\n**Viability assessment:**\n• Dating most accurate in 1st trimester (±3–5 days)\n• Later dating accuracy: ±1–2 weeks\n• U/S: BPD + femur length for estimation\n\n**Preterm-specific needs:**\n• **Plastic wrap <32 weeks** — cover body (not face) to prevent heat loss\n• **Higher starting FiO2** — 21–30% for ≥35 wk, 21–30% for <35 wk (titrate to SpO2 targets)\n• **Temperature is critical** — hypothermia worsens all outcomes\n• **Surfactant** may be needed if <32 wk (NICU decision)\n\n**Gestational age estimation if unknown:**\n• Weight: ~500g at 23–24 wk, ~1000g at 28 wk, ~1500g at 32 wk, ~2500g at 37 wk\n• Sole creases, ear cartilage, breast tissue for Ballard score (post-resuscitation)\n\n**Both hypothermia AND hyperthermia worsen outcomes.** Target normothermia (36.5–37.5°C) for all infants. [1]' WHERE id = 'nrp-preterm' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'INITIAL EVALUATION — The 3 Questions [1][2][3]\n\nAssess immediately at birth:\n\n**1. Term gestation?** (≥37 weeks)\n**2. Breathing or crying?**\n**3. Good muscle tone?** (flexed, active)' WHERE id = 'nrp-initial-eval' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'VIGOROUS NEWBORN\n\n• **Skin-to-skin** contact with mother\n• **Delayed cord clamping** 30–60 seconds\n• **Dry** the baby with warm towels\n• **Maintain normothermia** (36.5–37.5°C)\n• **APGAR scoring** at 1 and 5 minutes\n\nContinue monitoring for transition. If at any point the baby develops apnea, labored breathing, or HR <100 → proceed to initial steps.' WHERE id = 'nrp-routine' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'INITIAL STEPS — Complete within 30 seconds [1][2][3]\n\n**W — WARM**\n• Radiant heater ON — **NO blankets on top** (blocks radiant heat)\n• Plastic wrap for <32 weeks\n\n**D — DRY**\n• Vigorously dry with warm towels\n• Remove wet towels — replace with dry\n\n**P — POSITION**\n• **Sniffing position** — slight neck extension to open airway\n• Shoulder roll if needed for neutral alignment\n\n**S — STIMULATE**\n• **Flick the soles of the feet**\n• **Rub the back** — up and down along the spine\n• Primary apnea always responds to stimulation\n\n**C — CLEAR AIRWAY (PRN)**\n• Suction **mouth then nose** ("M before N")\n• Avoid vigorous or deep suctioning — causes bradycardia via vagal stimulation\n• Only suction if secretions are obstructing the airway' WHERE id = 'nrp-initial-steps' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'MECONIUM MANAGEMENT (2025 Update) [1][6]\n\n**Vigorous baby + meconium:**\n• Proceed with normal initial steps\n• No special suctioning needed\n\n**Non-vigorous baby + meconium:**\n• **Do NOT delay PPV for suctioning** (2025 guideline change)\n• Begin PPV as indicated — ventilation is the priority\n• ET suctioning **only if airway is obstructed** (visible thick meconium blocking airway)\n\n**Meconium aspirator** is no longer routinely recommended — it delays time to PPV without proven benefit. [1][6]\n\n**Key teaching point:** "Primary apnea responds to stimulation. **Secondary apnea does NOT** — it requires PPV." [2]' WHERE id = 'nrp-meconium' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'30-SECOND REASSESSMENT [1][2]\n\nAfter initial steps, evaluate:\n• **Breathing** — spontaneous, regular respirations?\n• **Heart rate** — auscultate or palpate umbilical stump (6 sec × 10)\n• **Tone** — flexed and active?\n• **Color** — improving?' WHERE id = 'nrp-golden30-eval' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'SUPPLEMENTAL O2 / CPAP [1][2]\n\n**Pulse oximetry** — apply to **right hand/wrist** (preductal)\n• Do NOT use left hand or feet (postductal — lower readings are normal)\n\n**SpO2 targets by minute of life:** [1]\n• 1 min: 60–65%\n• 2 min: 65–70%\n• 3 min: 70–75%\n• 4 min: 75–80%\n• 5 min: 80–85%\n• 10 min: 85–95%\n\n**Labored breathing with adequate HR:**\n• Start **CPAP 5–6 cmH2O** via mask\n• Supplement O2 to meet SpO2 targets\n• Avoid hyperoxia — titrate FiO2 down as saturations improve\n\n**If worsening or HR drops <100 → proceed to PPV**\n\nContinue monitoring. Most babies with labored breathing improve with CPAP alone.' WHERE id = 'nrp-breathing-support' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'PPV — The Most Important Intervention in NRP [1][2][3]\n\n**T-piece resuscitator preferred** (2025) — provides consistent PIP and PEEP. Self-inflating bag acceptable if T-piece unavailable. [1]\n\n**TECHNIQUE:**\n• **C-E grip** — C fingers seal mask, E fingers lift jaw\n• **Mask seal** — covers mouth and nose, not eyes\n• **Sniffing position** — slight neck extension\n• **PIP** 20–25 cmH2O (avoid barotrauma)\n• **Rate** 40–60/min ("squeeze—release—release")\n• **FiO2** start at 21% for ≥35 weeks; 21–30% for <35 weeks\n• **Confirm chest rise** and bilateral breath sounds\n\n**SpO2 TARGETS by minute:** [1]\n• 1 min: 60–65% → 2 min: 65–70% → 3 min: 70–75%\n• 4 min: 75–80% → 5 min: 80–85% → 10 min: 85–95%\n• Monitor on right hand/wrist (preductal)\n• **Avoid hyperoxia** — titrate FiO2 to targets\n\n**Ventilation is the single most important intervention.** Most neonatal bradycardia is caused by inadequate ventilation. [2]' WHERE id = 'nrp-ppv' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'PREDUCTAL SpO2 TARGETS [1][2]\n\nMonitor on **right hand/wrist** (preductal — above the ductus arteriosus).\n\n**Target SpO2 by minute of life:**\n• 1 min: 60–65%\n• 2 min: 65–70%\n• 3 min: 70–75%\n• 4 min: 75–80%\n• 5 min: 80–85%\n• 10 min: 85–95%\n\n**Why preductal?** The right hand receives blood from the aorta BEFORE the ductus arteriosus. Left hand and feet receive mixed blood — lower SpO2 is expected and doesn''t indicate poor oxygenation.\n\n**Titrate FiO2:**\n• Below target → increase FiO2 by 10–20%\n• Above target → decrease FiO2 by 10–20%\n• **Avoid hyperoxia** — especially in premature infants (retinopathy risk)\n\n**Cardiac monitor** (3-lead ECG) provides the most accurate HR — more reliable than pulse oximetry waveform during resuscitation. [1]' WHERE id = 'nrp-spo2-targets' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'PPV REASSESSMENT — after 30 seconds of effective PPV [1][2]\n\n**Check heart rate:**\n• Auscultate, palpate umbilical stump, or cardiac monitor\n• 6-second count × 10 for quick assessment' WHERE id = 'nrp-ppv-eval' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'MR SOPA — Corrective Steps for Ineffective Ventilation [1][2]\n\nIf HR is not improving with PPV, systematically troubleshoot:\n\n**M — Mask adjust**\n• Reapply mask — ensure tight seal, no air leak\n• Reposition C-E grip\n\n**R — Reposition**\n• Sniffing position — slight neck extension\n• Shoulder roll for alignment\n\n**S — Suction**\n• Suction mouth then nose\n• Clear any secretions obstructing airway\n\n**O — Open mouth**\n• Open baby''s mouth slightly\n• Jaw thrust if needed\n\n**P — Pressure increase**\n• Increase PIP by 5 cmH2O increments\n• Up to 30–40 cmH2O if needed for chest rise\n\n**A — Alternative airway**\n• Consider ETT intubation or LMA (supraglottic airway)\n• LMA may be used for ≥34 weeks, >2 kg (2025 update) [1]\n\nIf still no improvement after corrective steps → proceed to advanced airway.' WHERE id = 'nrp-corrective' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'ADVANCED AIRWAY — ETT or LMA [1][2]\n\n**ETT Intubation:**\n• Use **cardiac monitor** to confirm HR before and after\n• **Attempt limit:** 30 seconds per attempt — ventilate between attempts\n• Confirm placement: chest rise, bilateral breath sounds, CO2 detector\n• Secure tube — neonatal ETTs are extremely easy to dislodge\n\n**LMA / Supraglottic Airway (2025 update):**\n• May use as **initial interface** for ≥34 weeks, >2 kg [1]\n• Faster to place than ETT\n• Cannot suction through LMA — switch to ETT if tracheal suctioning needed\n\n**When to intubate:**\n• Failed PPV despite corrective steps\n• Need for chest compressions (intubation required before CPR)\n• Prolonged PPV anticipated\n• Tracheal suctioning for airway obstruction\n• Special circumstances: CDH (congenital diaphragmatic hernia)\n\nSee ETT sizing reference →' WHERE id = 'nrp-advanced-airway' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'NEONATAL ETT SIZING [1][2]\n\n**ETT size = Gestational Age (weeks) / 10**\n\n**Sizing table:**\n• 23–24 weeks → ETT **2.5**\n• 25–28 weeks → ETT **3.0**\n• 29–34 weeks → ETT **3.5**\n• ≥35 weeks → ETT **3.5–4.0**\n\n**Laryngoscope blade:**\n• **Miller 0** — most neonates\n• **Miller 00** — extreme preterm (<28 weeks)\n\n**ETT depth at lip:**\n• **6 + weight (kg) = cm at lip**\n• Example: 3 kg baby → 6 + 3 = 9 cm at lip\n\n**Securing tips:**\n• Hold tube to roof of mouth during securing\n• Neonatal ETTs are **extremely easy to dislodge** — secure firmly\n• Confirm with CO2 detector + bilateral breath sounds\n• Recheck position after every patient movement' WHERE id = 'nrp-ett-sizing' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'CRITICAL DECISION POINT [1][2]\n\nAfter ensuring effective ventilation (confirmed chest rise, corrective steps applied):\n\n**Is the heart rate still <60 bpm?**\n\nHR <60 despite effective PPV indicates the need for chest compressions.' WHERE id = 'nrp-hr60-check' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'NEONATAL CPR [1][2][3]\n\n**MUST secure airway first** — intubate or place LMA before starting compressions.\n\n**Technique — 2-thumb encircling:**\n• Both thumbs on **lower third of sternum**, just below the nipple line\n• Wrap fingers around the chest\n• Compress **1/3 of anteroposterior diameter**\n\n**Compression-to-ventilation ratio: 3:1**\n• "One—two—three—breathe" (120 events/min = 90 compressions + 30 breaths)\n• This is DIFFERENT from pediatric/adult CPR (15:2 or 30:2)\n\n**During CPR:**\n• Increase to **100% FiO2**\n• Establish vascular access: **UVC preferred** (fastest), IO as alternative\n• Prepare epinephrine\n\n**Goal: HR >60 bpm**\n• Reassess every 60 seconds\n• Once HR >60 → stop compressions, continue PPV\n• If HR remains <60 after 60 seconds of CPR → epinephrine [1][2]' WHERE id = 'nrp-cpr' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'CPR REASSESSMENT — after 60 seconds [1][2]\n\nPause compressions briefly to assess heart rate.\n\n**Is HR ≥60 bpm?**' WHERE id = 'nrp-cpr-eval' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'EPINEPHRINE — Neonatal Resuscitation [1][2][3]\n\n[Epinephrine](#/drug/epinephrine/neonatal resuscitation)\n\n**IV/IO (preferred):**\n• **0.01–0.03 mg/kg** of 1:10,000 (= 0.1–0.3 mL/kg)\n• Repeat every **3–5 minutes** as needed\n\n**ET (if no IV/IO access):**\n• **0.05–0.1 mg/kg** of 1:10,000 (= 0.5–1 mL/kg)\n• Higher dose needed via ET — absorption is unpredictable\n• Switch to IV/IO route as soon as access established\n\n**IV/IO is ALWAYS preferred over ET.** Establish UVC access as quickly as possible.\n\n**Preparation:**\n• Use **1:10,000 concentration** (0.1 mg/mL)\n• Pre-draw doses in labeled syringes\n• Flush with 1–3 mL NS after IV administration\n\n**Continue CPR between doses.** Do not stop compressions to give epinephrine. [1][2]' WHERE id = 'nrp-epinephrine' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'UVC PROCEDURE [1][2]\n\n**Umbilical cord anatomy:**\n• **2 arteries** — thick-walled, small lumen (at top of cross-section)\n• **1 vein** — thin-walled, large lumen (at bottom of cross-section)\n• **Catheterize the VEIN** — larger, easier to cannulate\n\n**Catheter size:**\n• **5 French** — term\n• **3.5 French** — preterm\n\n**Procedure:**\n1. Tie **umbilical tape** at base of stump — gentle tie to control bleeding\n2. Cut cord 1–2 cm above skin\n3. Identify the single large-lumen vein\n4. **Prime catheter** with NS\n5. Insert gently — **only 2–4 cm** until blood aspirates freely\n6. Do NOT advance further — risk of hepatic injury\n\n**IO access** is an acceptable alternative if UVC cannot be placed quickly.\n\n**Once access is established:** give IV epinephrine (preferred over ET route). [1][2]' WHERE id = 'nrp-uvc' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'PERSISTENT HR <60 AFTER EPINEPHRINE [1][2]\n\nIf the heart rate remains <60 after epinephrine and ongoing CPR, consider reversible causes:\n\n• **Hypovolemia** — maternal hemorrhage, placental abruption, cord avulsion\n• **Pneumothorax** — especially after vigorous PPV\n• **Equipment failure** — ETT displacement, monitor malfunction\n• **Prolonged resuscitation** — >20 minutes without response' WHERE id = 'nrp-persistent' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'VOLUME & GLUCOSE RESUSCITATION [1][2]\n\n**Hypovolemia — clinical signs:**\n• Pallor despite adequate oxygenation\n• Weak pulses\n• Poor response to resuscitation\n• Known maternal hemorrhage or placental abruption\n\n**Normal saline:**\n• **10 mL/kg** IV/IO — infuse over 5–10 minutes\n• May repeat if needed\n\n**O-negative pRBCs:**\n• **10 mL/kg** — for acute blood loss (abruption, cord avulsion)\n• Uncrossmatched O-negative\n\n**D10W (10% Dextrose):**\n• **2 mL/kg** IV — for hypoglycemia (glucose <40 mg/dL)\n• Neonates have limited glycogen stores — check glucose early\n\n**Naloxone:**\n• **No longer routinely recommended** in neonatal resuscitation\n• PPV is the treatment for respiratory depression, regardless of cause [1]\n\nReassess after volume — if HR improving → continue PPV → post-resuscitation care.' WHERE id = 'nrp-volume' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'WHEN TO CONSIDER STOPPING [1][4]\n\n**No detectable heart rate after 20 minutes of comprehensive resuscitation** (effective ventilation, chest compressions, epinephrine, volume) may be an appropriate time to discuss discontinuation.\n\n**Factors to consider:**\n• Gestational age and estimated viability\n• Duration of no detectable HR\n• Presence of any reversible causes\n• Parental wishes (if known)\n• Local institutional guidelines\n\n**Team and family discussion:**\n• Involve the family if possible\n• Communicate clearly and compassionately\n• Support the team — neonatal resuscitation discontinuation is emotionally difficult\n\n**Document everything:**\n• Time of birth, APGAR scores\n• All interventions and timing\n• Time of decision to discontinue\n• Who was present and involved in decision' WHERE id = 'nrp-discontinuation' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'POST-RESUSCITATION MONITORING [1][2]\n\n**APGAR scoring:**\n• Assess at **1, 5, and 10 minutes** after birth\n• Appearance, Pulse, Grimace, Activity, Respiration\n\n**Normothermia:**\n• Target **36.5–37.5°C** — monitor continuously\n• Both hypothermia AND hyperthermia worsen outcomes\n• **Therapeutic hypothermia** criteria: ≥36 weeks, moderate-severe HIE, initiated within 6 hours under NICU conditions — NOT during active resuscitation [1]\n\n**Glucose monitoring:**\n• Check within 30–60 minutes of stabilization\n• Treat if <40 mg/dL: D10W 2 mL/kg IV\n\n**NICU transfer:**\n• Any neonate requiring PPV or more should be evaluated by NICU\n• Communicate resuscitation details during handoff\n• Document: all interventions, timing, cord clamping time, APGARs\n\n**Family communication:**\n• Update parents on baby''s condition and plan\n• Allow skin-to-skin when stable\n\n**Team debrief:**\n• Review what went well and what could improve\n• Address emotional impact on team members [1][2]' WHERE id = 'nrp-postresus' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'Neonatal resuscitation algorithm overview — systematic stepwise approach from birth through compressions and epinephrine.\n\nReference: emergencymedicinecases.com' WHERE id = 'nrp-algorithm-ref' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'Neonatal resuscitation equipment sizing and setup reference — term vs preterm numbers, UVC anatomy, and monitoring placement.\n\nReference: Dr. Andrew Kitlowski MD, EM Simulation Cases' WHERE id = 'nrp-setup-ref' AND tree_id = 'neonatal-resus';
-- === neurosyphilis (10 nodes) ===
UPDATE decision_nodes SET body = E'Neurosyphilis should be considered in any patient with confirmed syphilis who has neurological symptoms or signs.\n\nThe diagnosis requires a combination of clinical, serologic, and CSF findings.\n\n**Key presentations:**\n• Visual changes, hearing loss\n• Cognitive impairment, psychiatric symptoms\n• Cranial nerve deficits, meningismus\n• Stroke-like symptoms\n• Tabes dorsalis (late)\n• General paresis (late)' WHERE id = 'ns-start' AND tree_id = 'neurosyphilis';
UPDATE decision_nodes SET body = E'CSF analysis is indicated for patients with syphilis and neurological symptoms.\n\n**Order:**\n• CSF-VDRL (highly specific, low sensitivity)\n• CSF FTA-ABS (more sensitive, less specific)\n• CSF cell count with differential\n• CSF protein\n• CSF glucose\n\n**Interpretation aids:**\n• CSF-VDRL reactive → diagnostic\n• CSF pleocytosis (>5 WBC/µL) → supportive\n• Elevated CSF protein → supportive\n• CSF FTA-ABS negative → helps rule out' WHERE id = 'ns-csf-eval' AND tree_id = 'neurosyphilis';
UPDATE decision_nodes SET body = E'A reactive CSF-VDRL is **diagnostic** of neurosyphilis.\n\n**First-line treatment:**\nAqueous crystalline penicillin G **18–24 million units/day** IV\n• 3–4 million units IV q4h, OR\n• Continuous infusion\n• Duration: **10–14 days**\n\n**Alternative (if IV not feasible):**\nProcaine penicillin 2.4 million units IM daily\nPLUS probenecid 500 mg PO QID\n× 10–14 days\n\n**PCN allergy:**\nDesensitization preferred. If not possible:\nCeftriaxone 2g IV/IM daily × 10–14 days (limited data)\n\n**Follow-up:**\n• Repeat CSF at 6 months\n• CSF pleocytosis should normalize first\n• Re-treat if CSF not improved at 6 months' WHERE id = 'ns-confirmed' AND tree_id = 'neurosyphilis';
UPDATE decision_nodes SET body = E'CSF-VDRL negative but CSF pleocytosis (>5 WBC/µL) or elevated protein with neurological symptoms → **treat as neurosyphilis**.\n\n**Treatment** (same as confirmed):\nAqueous crystalline penicillin G **18–24 million units/day** IV\n• 3–4 million units IV q4h × 10–14 days\n\n**Follow-up:**\n• Repeat CSF at 6 months\n• If CSF not improving, re-treat' WHERE id = 'ns-probable' AND tree_id = 'neurosyphilis';
UPDATE decision_nodes SET body = E'Normal CSF with non-reactive CSF-VDRL makes neurosyphilis unlikely.\n\n**Consider alternative diagnoses** for neurological symptoms.\n\n**Treat underlying syphilis stage:**\n• Early (primary/secondary/early latent): Benzathine PCN G 2.4M units IM × 1\n• Late latent: Benzathine PCN G 2.4M units IM weekly × 3 weeks\n\n**Re-evaluate** if symptoms progress or new neuro symptoms develop.' WHERE id = 'ns-unlikely' AND tree_id = 'neurosyphilis';
UPDATE decision_nodes SET body = E'Ocular and otosyphilis can occur at **any stage** of syphilis and require treatment as neurosyphilis **regardless of CSF findings**.\n\n**Ocular manifestations:**\n• Uveitis (most common), optic neuritis\n• Retinitis, papillitis\n• Vision loss\n\n**Otic manifestations:**\n• Sensorineural hearing loss\n• Tinnitus, vertigo\n\n**Treatment:**\nAqueous crystalline penicillin G **18–24 million units/day** IV\n• 3–4 million units IV q4h × 10–14 days\n\n**Consults:**\n• Ophthalmology (ocular involvement)\n• ENT/Audiology (otic involvement)\n• Infectious Disease\n\nCSF examination is recommended but treatment should NOT be delayed.' WHERE id = 'ns-ocular-otic' AND tree_id = 'neurosyphilis';
UPDATE decision_nodes SET body = E'Routine CSF examination is **NOT recommended** for asymptomatic late latent syphilis.\n\n**Exceptions — CSF exam IS indicated if:**\n• Treatment failure (titer not declining)\n• HIV co-infection with late latent syphilis\n• Neurological signs develop\n• Tertiary syphilis (aortitis, gumma)' WHERE id = 'ns-asymptomatic' AND tree_id = 'neurosyphilis';
UPDATE decision_nodes SET body = E'**First-line:**\nBenzathine penicillin G 2.4 million units IM weekly × 3 weeks\n(Total: 7.2 million units)\n\n**PCN allergy:**\nDesensitization preferred.\nAlternative: Doxycycline 100 mg PO BID × 28 days\n\n**Follow-up:**\n• Quantitative nontreponemal titers at 6, 12, and 24 months\n• 4-fold decline expected\n• If titers do not decline → evaluate for treatment failure, consider CSF exam' WHERE id = 'ns-latent-treatment' AND tree_id = 'neurosyphilis';
-- === nstemi (17 nodes) ===
UPDATE decision_nodes SET body = E'Establish diagnosis: [troponin rise](#/info/nstemi-troponin-sensitivity) AND at least one of ischemic symptoms, new ST depression/T-wave inversion, or wall motion abnormality.\n\n**Immediate actions:**\n• [Aspirin](#/drug/aspirin) 162–325 mg chewed\n• [Nitroglycerin](#/drug/nitroglycerin) 0.4 mg SL q5min × 3 — rule out RV infarction first\n• Morphine ONLY for refractory pain (may increase mortality)\n• Supplemental O₂ only if SpO₂ <90%\n• 12-lead ECG within 10 minutes\n• Serial troponins q3–6h' WHERE id = 'nstemi-start' AND tree_id = 'nstemi';
UPDATE decision_nodes SET body = E'Choose ONE anticoagulation strategy:\n• [Enoxaparin](#/drug/enoxaparin) 1 mg/kg SC q12h — preferred for most patients\n• [UFH](#/drug/ufh) 60 units/kg bolus (max 4,000), 12 units/kg/hr (max 1,000) — preferred if CrCl <30 or PCI within 24h\n• [Fondaparinux](#/drug/fondaparinux) 2.5 mg SC daily — preferred for conservative strategy (lowest bleeding risk per OASIS-5)\n\nDo NOT switch between anticoagulants (increases bleeding risk).' WHERE id = 'nstemi-initial-anticoag' AND tree_id = 'nstemi';
UPDATE decision_nodes SET body = E'Assess for features requiring emergent catheterization (<2 hours):\n• Hemodynamic instability (cardiogenic shock)\n• Refractory/recurrent chest pain despite medical therapy\n• Sustained ventricular arrhythmias (VT/VF)\n• Acute mitral regurgitation or VSD\n• Signs of heart failure (new pulmonary edema)' WHERE id = 'nstemi-risk-stratify' AND tree_id = 'nstemi';
UPDATE decision_nodes SET body = E'**Immediate PCI indicated.**\n• Activate cath lab\n• [UFH](#/drug/ufh) preferred anticoagulation (can titrate in cath lab)\n• If on fondaparinux: supplement with UFH 60 units/kg IV bolus (catheter thrombosis risk)\n• P2Y12 inhibitor loading: [Ticagrelor](#/drug/ticagrelor) 180 mg OR [Prasugrel](#/drug/prasugrel) 60 mg (if no prior stroke/TIA)\n• Consider [Metoprolol](#/drug/metoprolol) if HR >100 and no contraindications\n• Bedside [Echo (POCUS)](#/info/nstemi-pocus) for wall motion, EF, mechanical complications' WHERE id = 'nstemi-emergent' AND tree_id = 'nstemi';
UPDATE decision_nodes SET body = E'Low TIMI risk. Conservative management appropriate.\nSee [Conservative Management Details](#/info/nstemi-conservative)\n\nMedical therapy:\n• Continue anticoagulation (fondaparinux preferred — lowest bleeding)\n• [Metoprolol](#/drug/metoprolol) — target HR <70\n• [Nitroglycerin](#/drug/nitroglycerin) PRN chest pain\n• [Atorvastatin](#/drug/atorvastatin) 80 mg PO (start immediately)\n• Clopidogrel 300 mg loading if no P2Y12 yet (ticagrelor also acceptable)\n\nStress test before discharge.' WHERE id = 'nstemi-conservative' AND tree_id = 'nstemi';
UPDATE decision_nodes SET body = E'TIMI ≥4 (high risk). Cardiac catheterization within 24 hours.\n\n**Pre-PCI preparation:**\n• P2Y12 loading: [Ticagrelor](#/drug/ticagrelor) 180 mg preferred (PLATO: NNT 54 for CV death/MI/stroke)\n• Alternative: [Clopidogrel](#/drug/clopidogrel/acs) 600 mg if ticagrelor not available or on OAC\n• Continue anticoagulation (do NOT switch agents)\n• NPO (anticipate catheterization)\n• [Metoprolol](#/drug/metoprolol) — target HR <70 if tolerated\n• [Atorvastatin](#/drug/atorvastatin) 80 mg PO' WHERE id = 'nstemi-early-invasive' AND tree_id = 'nstemi';
UPDATE decision_nodes SET body = E'TIMI 3 (intermediate risk) or failed conservative strategy.\n\nCardiac catheterization within 25–72 hours.\n• Allows stabilization with medical therapy\n• Same pre-PCI preparation as early invasive\n• P2Y12 loading: [Ticagrelor](#/drug/ticagrelor) 180 mg OR [Clopidogrel](#/drug/clopidogrel/acs) 300–600 mg\n• If deferring P2Y12 until anatomy known: acceptable strategy per guidelines\n• Continue beta-blocker, statin, anticoagulation' WHERE id = 'nstemi-delayed-invasive' AND tree_id = 'nstemi';
UPDATE decision_nodes SET body = E'Select P2Y12 inhibitor for 12-month DAPT.\nSee [P2Y12 Selection Guide](#/info/nstemi-antiplatelet-cx)\n\n**Preferred:** [Ticagrelor](#/drug/ticagrelor) 90 mg BID\n• PLATO trial: reduced CV death/MI/stroke vs clopidogrel (NNT 54)\n• Aspirin ≤100 mg/day required\n\n**High ischemic risk (diabetes, stent thrombosis):** [Prasugrel](#/drug/prasugrel) 10 mg daily\n• TRITON-TIMI 38: more potent, but more bleeding\n• CONTRAINDICATED if prior stroke/TIA\n• Avoid if age ≥75 or weight <60 kg\n\n**High bleeding risk or on OAC:** [Clopidogrel](#/drug/clopidogrel/acs) 75 mg daily\n• Preferred for triple therapy (OAC + DAPT)\n• Least bleeding risk of the three' WHERE id = 'nstemi-post-pci' AND tree_id = 'nstemi';
UPDATE decision_nodes SET body = E'Coronary anatomy indicates CABG (e.g., left main, multivessel disease with diabetes).\n\n**P2Y12 hold times before surgery:**\n• [Ticagrelor](#/drug/ticagrelor): hold ≥3 days (minimum), ideally 5 days\n• [Clopidogrel](#/drug/clopidogrel/acs): hold ≥5 days\n• [Prasugrel](#/drug/prasugrel): hold ≥7 days\n\nContinue aspirin. Restart P2Y12 inhibitor 24–48h post-CABG.\nRefer cardiac surgery.' WHERE id = 'nstemi-cabg' AND tree_id = 'nstemi';
UPDATE decision_nodes SET body = E'Standard DAPT: 12 months post-PCI\n• Aspirin 81 mg + P2Y12 inhibitor daily\n\n**De-escalation options after 1–3 months if high bleeding risk:**\n• Switch from ticagrelor/prasugrel to clopidogrel (HOST-REDUCE trial)\n• Aspirin monotherapy after 1–3 months of DAPT (TWILIGHT trial)\n\n**Extended DAPT beyond 12 months:**\n• Consider if high ischemic risk (prior MI, diabetes, multivessel disease)\n• Ticagrelor 60 mg BID (PEGASUS-TIMI 54)\n\nIs this a MINOCA presentation?' WHERE id = 'nstemi-dapt-duration' AND tree_id = 'nstemi';
UPDATE decision_nodes SET body = E'Myocardial infarction with non-obstructive coronary arteries (≤50% stenosis on angiography). Present in 5–10% of MI patients.\n\nSee [MINOCA Workup & Management](#/info/nstemi-minoca)\n\n**Etiologies:**\n• Coronary spasm (most common)\n• Plaque disruption/erosion\n• Spontaneous coronary artery dissection (SCAD)\n• Takotsubo cardiomyopathy\n• Myocarditis\n\n**KEY:** Standard ACS regimens may be HARMFUL depending on etiology.\n• Coronary spasm: beta-blockers may worsen; use CCBs and nitrates\n• SCAD: anticoagulation may extend dissection; conservative preferred\n• Takotsubo: avoid catecholamines; supportive care\n• Myocarditis: avoid NSAIDs; treat underlying cause\n\nCardiac MRI recommended for all MINOCA patients.' WHERE id = 'nstemi-minoca' AND tree_id = 'nstemi';
UPDATE decision_nodes SET body = E'**The 5 pillars of post-ACS pharmacotherapy:**\n\n1. **DAPT:** Aspirin 81 mg + P2Y12 inhibitor × 12 months\n2. **Statin:** [Atorvastatin](#/drug/atorvastatin) 80 mg (or rosuvastatin 20–40 mg) — target LDL <70\n3. **Beta-blocker:** [Metoprolol](#/drug/metoprolol) succinate — continue if EF <40% or hypertension; may discontinue after 1 year if EF preserved\n4. **ACE inhibitor/ARB:** Start within 24h if EF ≤40%, hypertension, or diabetes. Consider for all post-ACS patients.\n5. **Aldosterone antagonist:** Add if EF ≤40% + HF symptoms or diabetes (EPHESUS trial)\n\nAlso: PPI if DAPT (GI prophylaxis — use pantoprazole, NOT omeprazole with clopidogrel)' WHERE id = 'nstemi-discharge' AND tree_id = 'nstemi';
UPDATE decision_nodes SET body = E'**Targets:**\n• BP <130/80 mmHg\n• LDL <70 mg/dL (consider <55 if very high risk)\n• HbA1c <7% (individualized)\n• BMI <25 (or waist <102 cm M, <88 cm F)\n• Smoking cessation — NNT 12 for mortality reduction\n\n**Cardiac rehabilitation:**\n• Class I recommendation (36 sessions over 12 weeks)\n• 25% relative reduction in cardiovascular mortality\n• Improves functional capacity, quality of life, depression\n\nDid the patient have atrial fibrillation detected?' WHERE id = 'nstemi-risk-factors' AND tree_id = 'nstemi';
UPDATE decision_nodes SET body = E'Patient requires both anticoagulation (AF) and DAPT (stent).\n\n**Triple therapy (OAC + aspirin + P2Y12) for SHORTEST possible duration:**\n• 1 week (if high bleeding risk) to 1 month maximum\n• Then dual therapy: OAC + [Clopidogrel](#/drug/clopidogrel/acs) 75 mg daily (preferred P2Y12 for triple/dual)\n• At 12 months: OAC alone (discontinue P2Y12)\n\n**Preferred DOAC:** Rivaroxaban 15 mg daily (PIONEER AF-PCI) or Apixaban 5 mg BID (AUGUSTUS)\n• Avoid warfarin if possible (more bleeding than DOAC-based regimens)\n• Avoid prasugrel in triple therapy (excess bleeding)\n• Avoid ticagrelor in triple therapy (limited data)' WHERE id = 'nstemi-triple-therapy' AND tree_id = 'nstemi';
UPDATE decision_nodes SET body = E'EF ≤40% post-MI = high-risk. Initiate guideline-directed medical therapy (GDMT):\n\n**Core GDMT (start before discharge):**\n• ACE inhibitor or ARB (or ARNI if stable) — SAVE, VALIANT trials\n• Beta-blocker ([Metoprolol](#/drug/metoprolol) succinate or carvedilol) — CAPRICORN trial\n• Aldosterone antagonist (eplerenone 25–50 mg or spironolactone) if EF ≤40% + HF symptoms or diabetes — EPHESUS trial\n• SGLT2 inhibitor (empagliflozin or dapagliflozin) — EMPEROR-Reduced, DAPA-HF\n\n**Reassess EF at 3 months.** If persistent EF ≤35%: evaluate for ICD (40 days post-MI minimum).\n\nContinue DAPT + statin as planned.' WHERE id = 'nstemi-hf-management' AND tree_id = 'nstemi';
UPDATE decision_nodes SET body = E'**Post-discharge follow-up:**\n• Cardiology: 1–2 weeks\n• PCP: 2–4 weeks\n• Cardiac rehab: referral before discharge (36 sessions)\n• Stress test at 4–6 weeks if not revascularized\n• Echo at 3 months if EF <50% at presentation\n• Lab work: lipid panel at 4–12 weeks (LDL target <70)\n\n**DAPT adherence counseling:**\n• Do NOT stop P2Y12 without cardiology guidance\n• Stent thrombosis risk highest in first 30 days\n• If surgery needed: consult cardiology for P2Y12 bridging plan\n• Carry medication list; inform all providers of stent placement\n\n**Red flags — return to ED:**\n• Chest pain lasting >15 minutes not relieved by nitroglycerin\n• Shortness of breath at rest or worsening\n• Syncope or near-syncope\n• Sustained palpitations' WHERE id = 'nstemi-followup' AND tree_id = 'nstemi';
-- === pe-treatment (14 nodes) ===
UPDATE decision_nodes SET body = E'Confirmed or high-probability acute pulmonary embolism. Risk stratification guides treatment.\n\nAssess **hemodynamic status** first:\n• SBP, heart rate, signs of shock\n• Bedside echo for RV strain\n• Troponin and BNP\n\nUse [PESI](#/calculator/pesi) or [sPESI](#/calculator/spesi) to risk-stratify normotensive patients.' WHERE id = 'pe-start' AND tree_id = 'pe-treatment';
UPDATE decision_nodes SET body = E'Sustained hypotension (SBP <90 mmHg or drop ≥40 mmHg for >15 min), cardiogenic shock, or cardiac arrest.\n\n**Mortality >15%** without immediate treatment.\n\n**ICD-10:** I26.02 (saddle embolus with acute cor pulmonale), I26.09, I26.90' WHERE id = 'pe-massive' AND tree_id = 'pe-treatment';
UPDATE decision_nodes SET body = E'**1. Anticoagulation** — start immediately:\n• [UFH](#/drug/ufh/pe) 80 units/kg bolus → 18 units/kg/hr infusion\n• Preferred over LMWH if thrombolysis anticipated\n\n**2. Systemic thrombolysis** (if no contraindications):\n• [Alteplase](#/drug/alteplase/pulmonary) 100 mg IV over 2 hours\n• OR accelerated regimen: 0.6 mg/kg (max 50 mg) over 15 min in cardiac arrest\n\n**3. If thrombolysis contraindicated:**\n• Catheter-directed therapy (CDT)\n• Surgical embolectomy\n• Consider ECMO as bridge in refractory shock\n\n**Volume resuscitation:** Cautious — >500 mL can worsen RV failure. Use vasopressors (norepinephrine preferred) for hemodynamic support.' WHERE id = 'pe-massive-tx' AND tree_id = 'pe-treatment';
UPDATE decision_nodes SET body = E'Normotensive but with evidence of RV strain or myocardial injury.\n\nAssess for **both**:\n• **RV dysfunction** — echo (RV/LV ratio >0.9, McConnell sign, TAPSE <16mm) or CT (RV/LV ≥0.9)\n• **Elevated biomarkers** — troponin AND/OR BNP/NT-proBNP' WHERE id = 'pe-submassive' AND tree_id = 'pe-treatment';
UPDATE decision_nodes SET body = E'**Anticoagulation** — start immediately:\n• [Enoxaparin](#/drug/enoxaparin/pe) 1 mg/kg SC q12h, OR\n• [UFH](#/drug/ufh/pe) if considering escalation to thrombolysis, OR\n• [Fondaparinux](#/drug/fondaparinux/pe) 5–10 mg SC daily (weight-based)\n\n**ICU monitoring recommended.** Watch closely for clinical deterioration.\n\n**Rescue thrombolysis** if hemodynamic decompensation:\n• [Alteplase](#/drug/alteplase/pulmonary) 100 mg IV over 2h\n• Half-dose alteplase (50 mg) may reduce bleeding risk — emerging evidence\n\n**Consider catheter-directed therapy** if thrombolysis contraindicated but patient deteriorating.' WHERE id = 'pe-submassive-high' AND tree_id = 'pe-treatment';
UPDATE decision_nodes SET body = E'Either RV dysfunction OR elevated biomarkers, but **not both**.\n\n**Anticoagulation alone** — thrombolysis not indicated:\n• [Enoxaparin](#/drug/enoxaparin/pe) 1 mg/kg SC q12h, OR\n• [UFH](#/drug/ufh/pe) if CrCl <30 or concern for rapid escalation\n\n**Hospital admission** for monitoring (typically step-down unit).\n\nReassess if clinical deterioration → escalate to intermediate-high risk pathway.' WHERE id = 'pe-submassive-low' AND tree_id = 'pe-treatment';
UPDATE decision_nodes SET body = E'No RV dysfunction on imaging, normal cardiac biomarkers, no hypotension.\n\n**PESI Class I–II** or **sPESI = 0**.\n\nUse [PESI](#/calculator/pesi) or [sPESI](#/calculator/spesi) to confirm low-risk classification.' WHERE id = 'pe-low-risk' AND tree_id = 'pe-treatment';
UPDATE decision_nodes SET body = E'Assess for **outpatient management** (Hestia criteria or institutional protocol):\n\n• Hemodynamically stable\n• No need for supplemental O₂\n• No active bleeding or high bleeding risk\n• No severe renal impairment (CrCl >30)\n• No severe pain requiring IV analgesics\n• Good social support and reliable follow-up\n• Able to take oral medications\n• No pregnancy' WHERE id = 'pe-outpatient-check' AND tree_id = 'pe-treatment';
UPDATE decision_nodes SET body = E'**DOACs preferred** (no parenteral bridge needed):\n• [Apixaban](#/drug/apixaban/pe) 10 mg BID × 7 days → 5 mg BID\n• [Rivaroxaban](#/drug/rivaroxaban/pe) 15 mg BID × 21 days → 20 mg daily with food\n\n**Follow-up:** Within 3–7 days with primary care or hematology.\n\n**Patient education:**\n• Return for worsening dyspnea, chest pain, hemoptysis, syncope\n• Adherence to anticoagulation is critical\n• Minimum 3 months of therapy; reassess for extended treatment' WHERE id = 'pe-outpatient-tx' AND tree_id = 'pe-treatment';
UPDATE decision_nodes SET body = E'Admit for **24–48h observation** with initiation of anticoagulation.\n\nStart oral DOAC therapy:\n• [Apixaban](#/drug/apixaban/pe) 10 mg BID × 7 days → 5 mg BID, OR\n• [Rivaroxaban](#/drug/rivaroxaban/pe) 15 mg BID × 21 days → 20 mg daily\n\nTransition to outpatient when clinically stable and oral intake confirmed.' WHERE id = 'pe-inpatient-low' AND tree_id = 'pe-treatment';
UPDATE decision_nodes SET body = E'Choice depends on renal function, bleeding risk, patient preference, and cost.\n\n**Key decision points:**\n• CrCl <30 mL/min → UFH preferred\n• Cancer-associated VTE → DOAC (apixaban/rivaroxaban) or LMWH\n• Pregnancy → LMWH only (DOACs contraindicated)\n• HIT → argatroban or fondaparinux' WHERE id = 'pe-anticoag-selection' AND tree_id = 'pe-treatment';
UPDATE decision_nodes SET body = E'**Single-drug approach (no parenteral lead-in):**\n• [Apixaban](#/drug/apixaban/pe) 10 mg BID × 7 days → 5 mg BID\n• [Rivaroxaban](#/drug/rivaroxaban/pe) 15 mg BID × 21 days → 20 mg daily (with food)\n\n**Parenteral lead-in required (5–10 days LMWH/UFH first):**\n• [Edoxaban](#/drug/edoxaban/pe) 60 mg daily (30 mg if CrCl 15–50, weight ≤60 kg, or P-gp inhibitor)\n• [Dabigatran](#/drug/dabigatran/pe) 150 mg BID\n\n**Duration:** Minimum 3 months. Extended treatment for unprovoked PE, recurrent VTE, or persistent risk factors.' WHERE id = 'pe-doac' AND tree_id = 'pe-treatment';
UPDATE decision_nodes SET body = E'• [Enoxaparin](#/drug/enoxaparin/pe) 1 mg/kg SC q12h (or 1.5 mg/kg daily)\n• Start warfarin on day 1 — overlap until INR 2.0–3.0 for ≥24 hours\n• Discontinue LMWH after INR therapeutic × 2 consecutive days\n• Target INR: 2.0–3.0\n\n**Duration:** Minimum 3 months. Extended for unprovoked or recurrent VTE.\n\n**Monitoring:** INR weekly until stable, then monthly.' WHERE id = 'pe-lmwh-warfarin' AND tree_id = 'pe-treatment';
UPDATE decision_nodes SET body = E'**CrCl <30 mL/min:**\n• [UFH](#/drug/ufh/pe) preferred — renally independent clearance\n• Adjust LMWH dose for CrCl 15–30 (enoxaparin 1 mg/kg SC daily)\n• Apixaban may be used cautiously (least renal elimination of DOACs)\n\n**Severe hepatic disease (Child-Pugh C):**\n• UFH preferred\n• DOACs contraindicated in severe hepatic impairment\n\n**HIT (heparin-induced thrombocytopenia):**\n• Discontinue ALL heparin products immediately\n• [Fondaparinux](#/drug/fondaparinux/pe) or argatroban as alternatives\n• Bridge to warfarin only after platelet recovery (>150k)' WHERE id = 'pe-renal-hepatic' AND tree_id = 'pe-treatment';
-- === peds-fever (37 nodes) ===
UPDATE decision_nodes SET body = E'**Fever Without a Source (FWS):** T ≥38°C (100.4°F) rectally in an infant 0–6 months with no identifiable source on history and physical exam.\n\nREFERENCES\n• [HSV Workup Criteria](#/info/pf-hsv-criteria)\n• [UTI Risk Factors](#/info/pf-uti-risk)\n• [Ceftriaxone Contraindications](#/info/pf-ceftriaxone-ci)\n• [Antimicrobial Dosing](#/info/pf-abx-dosing)\n\nSelect the patient’s age:' WHERE id = 'pf-start' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Patient meets one or more exclusion criteria for the FWS pathway.\n\nEXCLUSION CRITERIA\n• Preterm (<37 weeks gestational age)\n• Immunocompromised\n• Indwelling devices (VP shunt, central line)\n• Known immune deficiency\n• Recent hospitalization (within 7 days)\n• Current antibiotics or recent (<48h)\n\nOFF-PATHWAY TRIGGERS\n• Focal bacterial infection identified (cellulitis, abscess, pneumonia, osteomyelitis)\n• Hypothermia (<36°C / 96.8°F)\n• Bronchiolitis with clear viral syndrome\n• Clinically ill-appearing (not toxic, but not well)' WHERE id = 'pf-off-pathway' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Ill-appearing infant requires full sepsis workup and empiric antibiotics regardless of age.\n\nFULL SEPSIS WORKUP\n• CBC with differential\n• Blood culture\n• CMP\n• UA + urine culture (catheterized)\n• Lumbar puncture: CSF cell count, glucose, protein, Gram stain, culture, meningitis/encephalitis PCR panel\n• Consider: CRP, Procalcitonin, stool culture (if diarrhea)\n• Consider: [HSV workup](#/info/pf-hsv-criteria) if <21 days or risk factors\n\nEMPIRIC ANTIBIOTICS BY AGE\n• **0–7 days:** [Ampicillin](#/drug/ampicillin) + [Gentamicin](#/drug/gentamicin)\n• **8–28 days:** [Ceftriaxone](#/drug/ceftriaxone/pediatric fever) (or [Cefepime](#/drug/cefepime) if [CI](#/info/pf-ceftriaxone-ci)) + [Ampicillin](#/drug/ampicillin)\n• **29–60 days:** [Ceftriaxone](#/drug/ceftriaxone/pediatric fever) + [Vancomycin](#/drug/vancomycin)\n• **>60 days:** [Ceftriaxone](#/drug/ceftriaxone/pediatric fever) + [Vancomycin](#/drug/vancomycin)\n\nSee [Antimicrobial Dosing Reference](#/info/pf-abx-dosing) for weight-based doses.' WHERE id = 'pf-toxic' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Does the infant have any of the following off-pathway triggers?\n\n• Focal bacterial infection (cellulitis, abscess, pneumonia, osteomyelitis)\n• Hypothermia (<36°C / 96.8°F)\n• Bronchiolitis with clear viral syndrome\n• Clinically ill-appearing' WHERE id = 'pf-neo-screen' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'**All 0–21 day neonates require full sepsis workup including LP.**\n\nLABS TO ORDER\n• CBC with differential\n• Blood culture\n• CMP\n• UA (catheterized) — if positive, send urine culture\n• Lumbar puncture:\n  – CSF cell count with differential\n  – CSF glucose, protein\n  – CSF Gram stain\n  – CSF culture\n  – Meningitis/encephalitis PCR panel\n  – Hold tube #4 (for HSV PCR if needed)\n\nOPTIONAL\n• CRP, Procalcitonin\n• Stool culture (if diarrhea present)' WHERE id = 'pf-neo-labs' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Does the infant have [HSV risk factors or clinical features](#/info/pf-hsv-criteria)?\n\n• Skin vesicles (mouth, scalp, trunk)\n• Seizures\n• Lethargy, poor feeding\n• Hepatosplenomegaly\n• Thrombocytopenia or transaminitis\n• CSF pleocytosis\n• Maternal HSV history' WHERE id = 'pf-neo-hsv' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'**Add [Acyclovir](#/drug/acyclovir) 20 mg/kg IV q8h**\n\nHSV TESTING TO ORDER\n• HSV PCR — blood (plasma)\n• HSV PCR — CSF (from held tube #4)\n• Surface cultures: conjunctiva, throat, nasopharynx, rectum\n• Vesicle fluid: viral culture + PCR (if lesions present)\n• AST, ALT (hepatic involvement screen)\n\nDURATION\n• Minimum 5 doses or until HSV PCR results negative\n• If PCR not resulted after 5 doses → contact Infectious Disease\n• Ensure adequate hydration (crystalline nephropathy risk)' WHERE id = 'pf-neo-hsv-rx' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Select the neonate’s age to determine the appropriate empiric regimen.\n\nSee [Antimicrobial Dosing Reference](#/info/pf-abx-dosing) for complete dosing table.' WHERE id = 'pf-neo-age' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Review CSF results from the lumbar puncture.\n\n**ABNORMAL CSF (0–28 days):**\n• WBC >15 cells/mm³\n• Positive Gram stain\n• Traumatic tap or uninterpretable\n\nNote: Traumatic taps are common in neonates. If bloody, use correction ratio or treat as if abnormal.' WHERE id = 'pf-neo-csf' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'**Escalate to meningitic dosing based on age:**\n\n**0–7 DAYS**\n• [Ampicillin](#/drug/ampicillin) 100 mg/kg IV q8h (meningitic dose)\n• Add [Cefepime](#/drug/cefepime) 50 mg/kg IV q12h\n• Discontinue [Gentamicin](#/drug/gentamicin)\n• Consider [Acyclovir](#/drug/acyclovir) if not already started\n\n**8–21 DAYS**\n• [Ceftriaxone](#/drug/ceftriaxone/pediatric meningitis) 50 mg/kg IV q12h (meningitic dose)\n• Add [Ampicillin](#/drug/ampicillin) 75 mg/kg IV q6h (meningitic dose)\n• Consider [Acyclovir](#/drug/acyclovir) if not already started\n\nSee [Antimicrobial Dosing Reference](#/info/pf-abx-dosing) for complete dosing.' WHERE id = 'pf-neo-mening' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'**ALL 0–21 day neonates are admitted** regardless of clinical appearance or lab results.\n\nINPATIENT MANAGEMENT\n• Continue empiric antibiotics pending culture results\n• Blood cultures: finalized at 24–36 hours\n• CSF cultures: finalized at 48–72 hours\n\nIF PATHOGEN IDENTIFIED\n• Narrow antibiotics to targeted therapy\n• Duration based on organism and site\n\nIF NO PATHOGEN AT 24–36 HOURS + WELL-APPEARING\n• Discontinue antimicrobials\n• Observe for clinical stability\n• Manage supportively for duration of illness' WHERE id = 'pf-neo-admit' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Does the infant have any of the following off-pathway triggers?\n\n• Focal bacterial infection identified\n• Hypothermia (<36°C / 96.8°F)\n• Bronchiolitis with clear viral syndrome\n• Clinically ill-appearing' WHERE id = 'pf-22-screen' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'LABS TO ORDER\n• CBC with differential\n• Blood culture\n• CMP\n• **Procalcitonin (PCT)**\n• UA (catheterized) — if positive, send urine culture\n\nOPTIONAL\n• CRP\n• Stool culture (if diarrhea present)\n\nLP is not automatically required for this age group — it depends on inflammatory marker results and shared decision-making.' WHERE id = 'pf-22-labs' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Are ANY of the following inflammatory markers abnormal?\n\n**ABNORMAL CRITERIA:**\n• Temperature >38.5°C (101.3°F)\n• Procalcitonin >0.5 ng/mL\n• CRP >2.0 mg/dL\n• ANC >4,000 cells/mm³\n\nAny single abnormal marker → higher risk.\nAll normal → lower risk but still requires evaluation.' WHERE id = 'pf-22-im' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Lumbar puncture is recommended if inflammatory markers are abnormal. For normal markers, LP is a shared decision with the family.\n\n**ABNORMAL CSF (22–28 days):**\n• WBC >15 cells/mm³\n• Positive Gram stain' WHERE id = 'pf-22-lp' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'**MENINGITIS DOSING (22–28 DAYS)**\n• [Ceftriaxone](#/drug/ceftriaxone/pediatric meningitis) 50 mg/kg IV q12h (meningitic dose)\n• Add [Ampicillin](#/drug/ampicillin) 75 mg/kg IV q6h (meningitic dose)\n• Consider [Acyclovir](#/drug/acyclovir) 20 mg/kg IV q8h if HSV risk factors\n\nSee [Antimicrobial Dosing Reference](#/info/pf-abx-dosing) for complete dosing.' WHERE id = 'pf-22-mening' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Review the [urinalysis results](#/info/pf-ua-interpret).\n\n**Positive UA:** Leukocyte esterase, nitrites, >5 WBC/hpf, or bacteria on Gram stain.\n\nIf UA positive, ensure catheterized urine culture was sent.' WHERE id = 'pf-22-ua' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'**ANTIBIOTIC TREATMENT**\n• [Cefazolin](#/drug/cefazolin) 17 mg/kg IV q8h (without bacteremia)\n• [Cefazolin](#/drug/cefazolin) 33 mg/kg IV q8h (with concurrent bacteremia)\n• Step-down to [Cephalexin](#/drug/cephalexin) 17 mg/kg PO TID when tolerating PO\n• Total duration: 10 days (IV + PO combined)\n\nADMIT for IV antibiotics and monitoring.' WHERE id = 'pf-22-uti' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Normal CSF and negative UA. Disposition depends on inflammatory marker status and shared decision-making with the family.\n\n**IF ABNORMAL INFLAMMATORY MARKERS:**\nHigher risk — admission preferred. If family elects home observation:\n• [Ceftriaxone](#/drug/ceftriaxone/pediatric fever) 50 mg/kg IM/IV x1 before discharge\n• Mandatory follow-up in 24 hours\n\n**IF NORMAL INFLAMMATORY MARKERS:**\nLower risk — home observation is reasonable.\n• Antibiotics optional (prefer off antibiotics)\n• Follow-up in 24 hours' WHERE id = 'pf-22-sdm' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'**IF DISCHARGED HOME**\n• Review [Discharge Criteria](#/info/pf-discharge) — all must be met\n• Consider [Ceftriaxone](#/drug/ceftriaxone/pediatric fever) 50 mg/kg IM/IV x1 if inflammatory markers abnormal\n• Mandatory PCP or ED follow-up within 24 hours\n• Provide [Return Precautions](#/info/pf-discharge)\n• Culture callback: blood culture results at 24–36h\n\n**IF ADMITTED**\n• Continue observation\n• If abnormal inflammatory markers: may give [Ceftriaxone](#/drug/ceftriaxone/pediatric fever) 50 mg/kg IV q24h\n• If normal inflammatory markers: prefer off antibiotics, discuss close observation\n• Culture results at 24–36h determine next steps\n\n**IF LP NOT PERFORMED**\n• Abnormal inflammatory markers: recommend admission, prefer off antibiotics but may give Ceftriaxone\n• Normal inflammatory markers: home observation reasonable with 24h follow-up' WHERE id = 'pf-22-dispo' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Does the infant have any of the following off-pathway triggers?\n\n• Focal bacterial infection identified\n• Hypothermia (<36°C / 96.8°F)\n• Bronchiolitis with clear viral syndrome\n• Clinically ill-appearing' WHERE id = 'pf-60-screen' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'LABS TO ORDER\n• CBC with differential\n• Blood culture\n• CMP\n• **Procalcitonin (PCT)**\n• UA (catheterized) — if positive, send urine culture\n\nOPTIONAL\n• CRP\n• Stool culture (if diarrhea present)\n\nLP is determined by inflammatory marker results.' WHERE id = 'pf-60-labs' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Are ANY of the following inflammatory markers abnormal?\n\n**ABNORMAL CRITERIA:**\n• Temperature >38.5°C (101.3°F)\n• Procalcitonin >0.5 ng/mL\n• CRP >2.0 mg/dL\n• ANC >4,000 cells/mm³\n\nAny single abnormal marker → higher risk → LP recommended.\nAll normal → lower risk → no LP needed.' WHERE id = 'pf-60-im' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Lumbar puncture recommended for elevated inflammatory markers.\n\n**ABNORMAL CSF (29–60 days):**\n• WBC >9 cells/mm³ (lower threshold than 0–28 days)\n• Positive Gram stain' WHERE id = 'pf-60-lp' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'**MENINGITIS DOSING (29–60 DAYS)**\n• [Ceftriaxone](#/drug/ceftriaxone/pediatric meningitis) 50 mg/kg IV q12h (meningitic dose)\n• Add [Vancomycin](#/drug/vancomycin) 15 mg/kg IV q6h\n• Consider [Acyclovir](#/drug/acyclovir) 20 mg/kg IV q8h if HSV risk factors\n\nNote: [Vancomycin](#/drug/vancomycin) added (instead of [Ampicillin](#/drug/ampicillin)) to cover MRSA and resistant GBS/pneumococcus in this age group.\n\nSee [Antimicrobial Dosing Reference](#/info/pf-abx-dosing) for complete dosing.' WHERE id = 'pf-60-mening' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Review the [urinalysis results](#/info/pf-ua-interpret).\n\n**Positive UA:** Leukocyte esterase, nitrites, >5 WBC/hpf, or bacteria on Gram stain.\n\nIf UA positive, ensure catheterized urine culture was sent.' WHERE id = 'pf-60-ua' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'**ANTIBIOTIC TREATMENT**\n• [Cefazolin](#/drug/cefazolin) 17 mg/kg IV q8h (without bacteremia)\n• [Cefazolin](#/drug/cefazolin) 33 mg/kg IV q8h (with concurrent bacteremia)\n• Step-down to [Cephalexin](#/drug/cephalexin) 17 mg/kg PO TID when tolerating PO\n• Total duration: 10 days (IV + PO combined)\n\nADMIT for IV antibiotics and monitoring.' WHERE id = 'pf-60-uti' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Abnormal inflammatory markers but normal CSF and negative UA.\n\n• [Ceftriaxone](#/drug/ceftriaxone/pediatric fever) 50 mg/kg IM/IV x1 recommended\n• Home observation with mandatory 24-hour follow-up\n• OR admit for observation' WHERE id = 'pf-60-sdm' AND tree_id = 'peds-fever';
COMMIT;
